     9→import { indexedDBService } from './indexedDB';
    10→import { logger } from './logger';
    11→
    12→const log = logger.module('BrainBackup');
    13→
    14→// Extend Window interface for File System Access API
    15→declare global {
    16→  interface Window {
    17→    showDirectoryPicker?: (options?: { mode?: 'read' | 'readwrite' }) => Promise<FileSystemDirectoryHandle>;
    18→  }
    19→}
