    21→export interface BrainBackup {
    22→  version: string;
    23→  exportDate: string;
    24→  appVersion: string;
    25→  compressed?: boolean;
    26→  data: Record<string, any>;
    27→}
    28→
    29→export interface ExportOptions {
    30→  compressed?: boolean;
