    43→/**
    44→ * Compress data using gzip
    45→ */
    46→const compressData = async (data: string): Promise<Blob> => {
    47→  const blob = new Blob([data]);
    48→  const stream = blob.stream();
    49→  const compressedStream = stream.pipeThrough(new CompressionStream('gzip'));
    50→  return new Response(compressedStream).blob();
    51→};
    52→
    53→/**
    54→ * Decompress gzip data
    55→ */
    56→const decompressData = async (blob: Blob): Promise<string> => {
    57→  const stream = blob.stream();
    58→  const decompressedStream = stream.pipeThrough(new DecompressionStream('gzip'));
    59→  return new Response(decompressedStream).text();
    60→};
