    62→/**
    63→ * Format bytes to human-readable size
    64→ */
    65→export const formatFileSize = (bytes: number): string => {
    66→  if (bytes === 0) return '0 Bytes';
    67→  const k = 1024;
    68→  const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    69→  const i = Math.floor(Math.log(bytes) / Math.log(k));
    70→  return `${Math.round((bytes / Math.pow(k, i)) * 100) / 100} ${sizes[i]}`;
    71→};
