    73→/**
    74→ * Optimize object for compression
    75→ * - Sorts keys alphabetically (helps gzip find patterns)
    76→ * - Removes empty objects/arrays (reduces JSON size)
    77→ * - Recursively processes nested objects
    78→ */
    79→const optimizeForCompression = (obj: any): any => {
    80→  if (obj === null || obj === undefined) return obj;
    81→
    82→  if (Array.isArray(obj)) {
    83→    // Process array items, filter out empty objects/arrays
    84→    return obj
    85→      .map(item => optimizeForCompression(item))
    86→      .filter(item => {
    87→        if (item === null || item === undefined) return false;
    88→        if (typeof item === 'object' && Object.keys(item).length === 0) return false;
    89→        if (Array.isArray(item) && item.length === 0) return false;
    90→        return true;
    91→      });
    92→  }
    93→
    94→  if (typeof obj === 'object') {
    95→    // Sort keys and process values
    96→    const sorted: Record<string, any> = {};
    97→    const keys = Object.keys(obj).sort();
    98→
    99→    for (const key of keys) {
   100→      const value = optimizeForCompression(obj[key]);
   101→      // Only include non-empty values
   102→      if (value !== null && value !== undefined) {
   103→        if (typeof value === 'object' && !Array.isArray(value) && Object.keys(value).length === 0) {
   104→          continue; // Skip empty objects
   105→        }
   106→        if (Array.isArray(value) && value.length === 0) {
   107→          continue; // Skip empty arrays
   108→        }
   109→        sorted[key] = value;
   110→      }
   111→    }
   112→
   113→    return sorted;
   114→  }
   115→
   116→  return obj;
   117→};
