   119→/**
   120→ * Export all data to a .brain file
   121→ */
   122→export const exportBrainFile = async (options: ExportOptions = {}): Promise<ExportResult> => {
   123→  const { compressed = true, prettyPrint = false } = options;
   124→
   125→  try {
   126→    log.info('Exporting brain data');
   127→
   128→    // Get all data from IndexedDB
   129→    const allData = await indexedDBService.getAllData();
   130→
   131→    // Parse JSON values for cleaner export
   132→    const parsedData: Record<string, any> = {};
   133→    for (const [key, value] of Object.entries(allData)) {
   134→      try {
   135→        parsedData[key] = JSON.parse(value);
   136→      } catch {
   137→        // If not JSON, store as-is
   138→        parsedData[key] = value;
   139→      }
   140→    }
   141→
   142→    // Create backup object
   143→    const backup: BrainBackup = {
   144→      version: BACKUP_VERSION,
   145→      exportDate: new Date().toISOString(),
   146→      appVersion: APP_VERSION,
   147→      compressed,
   148→      data: parsedData,
   149→    };
   150→
   151→    // Optimize for compression if enabled (sorts keys, removes empty values)
   152→    const finalBackup = compressed ? optimizeForCompression(backup) : backup;
   153→
   154→    // Convert to JSON string
   155→    const jsonString = JSON.stringify(finalBackup, null, prettyPrint ? 2 : 0);
   156→
   157→    // Create blob (compressed or uncompressed)
   158→    let blob: Blob;
   159→    let fileSize: number;
   160→
   161→    if (compressed) {
   162→      blob = await compressData(jsonString);
   163→      fileSize = blob.size;
   164→      log.debug('Compressed', { original: formatFileSize(jsonString.length), compressed: formatFileSize(fileSize) });
   165→    } else {
   166→      blob = new Blob([jsonString], { type: 'application/json' });
   167→      fileSize = blob.size;
   168→    }
   169→
   170→    // Create download link
   171→    const url = URL.createObjectURL(blob);
   172→    const link = document.createElement('a');
   173→    link.href = url;
   174→
   175→    // Generate filename with timestamp
   176→    const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, -5);
   177→    const filename = `NeumanBrain-Backup-${timestamp}.brain`;
   178→    link.download = filename;
   179→
   180→    // Trigger download
   181→    document.body.appendChild(link);
   182→    link.click();
   183→
   184→    // Cleanup
   185→    document.body.removeChild(link);
   186→    URL.revokeObjectURL(url);
   187→
   188→    log.info('Brain data exported successfully');
   189→
   190→    return {
   191→      filename,
   192→      size: fileSize,
   193→      compressed,
   194→    };
   195→  } catch (error) {
   196→    log.error('Failed to export brain data', { error });
   197→    throw new Error(`Export failed: ${error}`);
   198→  }
   199→};
