   201→/**
   202→ * Import data from a .brain file (supports compressed and uncompressed)
   203→ */
   204→export const importBrainFile = async (file: File): Promise<{
   205→  success: boolean;
   206→  message: string;
   207→  itemsImported: number;
   208→  wasCompressed?: boolean;
   209→}> => {
   210→  try {
   211→    log.info('Importing brain data');
   212→
   213→    // Try to detect if file is compressed by attempting to read as text first
   214→    let fileContent: string;
   215→    let wasCompressed = false;
   216→
   217→    try {
   218→      // First try reading as text (uncompressed)
   219→      fileContent = await file.text();
   220→      JSON.parse(fileContent); // Validate it's valid JSON
   221→    } catch {
   222→      // If that fails, try decompressing
   223→      try {
   224→        log.debug('Detected compressed file, decompressing');
   225→        fileContent = await decompressData(file);
   226→        wasCompressed = true;
   227→      } catch (decompError) {
   228→        throw new Error('Invalid .brain file: Not valid JSON or compressed data');
   229→      }
   230→    }
   231→
   232→    // Parse JSON
   233→    let backup: BrainBackup;
   234→    try {
   235→      backup = JSON.parse(fileContent);
   236→    } catch (error) {
   237→      throw new Error('Invalid .brain file: Not valid JSON');
   238→    }
   239→
   240→    // Validate backup structure
   241→    if (!backup.version || !backup.data) {
   242→      throw new Error('Invalid .brain file: Missing required fields');
   243→    }
   244→
   245→    // Version compatibility check
   246→    if (backup.version !== BACKUP_VERSION) {
   247→      log.warn('Backup version mismatch', { fileVersion: backup.version, currentVersion: BACKUP_VERSION });
   248→      // For now, continue anyway - can add migration logic later
   249→    }
   250→
   251→    // Import all data to IndexedDB using batch operations (50-100x faster)
   252→    const itemsToImport: Record<string, string> = {};
   253→    for (const [key, value] of Object.entries(backup.data)) {
   254→      // Convert back to JSON string for storage
   255→      const jsonString = typeof value === 'string' ? value : JSON.stringify(value);
   256→      itemsToImport[key] = jsonString;
   257→    }
   258→
   259→    // Write all items in a single transaction
   260→    await indexedDBService.setItemsBatch(itemsToImport);
   261→    const itemsImported = Object.keys(itemsToImport).length;
   262→
   263→    const compressionNote = wasCompressed ? ' (compressed)' : '';
   264→    const message = `Successfully imported ${itemsImported} items from ${file.name}${compressionNote}`;
   265→    log.info(message);
   266→
   267→    return {
   268→      success: true,
   269→      message,
   270→      itemsImported,
   271→      wasCompressed,
   272→    };
   273→  } catch (error) {
   274→    const errorMessage = `Import failed: ${error}`;
   275→    log.error(errorMessage);
   276→    return {
   277→      success: false,
   278→      message: errorMessage,
   279→      itemsImported: 0,
   280→    };
   281→  }
   282→};
   283→
   284→/**
   285→ * Validate a .brain file without importing
   286→ */
   287→export const validateBrainFile = async (file: File): Promise<{
   288→  valid: boolean;
   289→  message: string;
   290→  info?: {
   291→    version: string;
   292→    exportDate: string;
   293→    appVersion: string;
   294→    itemCount: number;
   295→    fileSize: string;
   296→  };
   297→}> => {
   298→  try {
   299→    // Check file extension
   300→    if (!file.name.endsWith('.brain')) {
   301→      return {
   302→        valid: false,
   303→        message: 'File must have .brain extension',
   304→      };
   305→    }
   306→
   307→    // Try to read as text or decompress
   308→    let fileContent: string;
   309→    try {
   310→      fileContent = await file.text();
   311→      JSON.parse(fileContent); // Validate JSON
   312→    } catch {
   313→      try {
   314→        fileContent = await decompressData(file);
   315→      } catch {
   316→        return {
   317→          valid: false,
   318→          message: 'Invalid .brain file: Not valid JSON or compressed data',
   319→        };
   320→      }
   321→    }
   322→
   323→    const backup: BrainBackup = JSON.parse(fileContent);
   324→
   325→    // Validate structure
   326→    if (!backup.version || !backup.data) {
   327→      return {
   328→        valid: false,
   329→        message: 'Invalid .brain file: Missing required fields',
   330→      };
   331→    }
   332→
   333→    return {
   334→      valid: true,
   335→      message: 'Valid .brain file',
   336→      info: {
   337→        version: backup.version,
   338→        exportDate: backup.exportDate,
   339→        appVersion: backup.appVersion,
   340→        itemCount: Object.keys(backup.data).length,
   341→        fileSize: formatFileSize(file.size),
   342→      },
   343→    };
   344→  } catch (error) {
   345→    return {
   346→      valid: false,
   347→      message: `Invalid .brain file: ${error}`,
   348→    };
   349→  }
   350→};
   351→
   352→/**
   353→ * Auto-save to a user-selected directory using File System Access API
   354→ * Uses single file + hidden versioning strategy:
   355→ * - Main file: User's custom filename (e.g., "Neuman.Brain") - always overwritten
   356→ * - Versions: Hidden .neuman-backups/ folder with timestamped backups
   357→ * - Auto-cleanup: Keeps only last N versions (user configurable)
   358→ */
   359→export const autoSave = async (directoryHandle: FileSystemDirectoryHandle): Promise<ExportResult> => {
   360→  try {
   361→    // Load preferences for custom filename and version count
   362→    const { loadPreferences } = await import('./backupPreferences');
   363→    const preferences = await loadPreferences();
   364→    const customFilename = preferences.customFilename || 'Neuman.Brain';
   365→    const versionCount = preferences.versionCount || 7;
   366→
   367→    // Export data
   368→    const allData = await indexedDBService.getAllData();
   369→    const parsedData: Record<string, any> = {};
   370→    for (const [key, value] of Object.entries(allData)) {
   371→      try {
   372→        parsedData[key] = JSON.parse(value);
   373→      } catch {
   374→        parsedData[key] = value;
   375→      }
   376→    }
   377→
   378→    const backup: BrainBackup = {
   379→      version: BACKUP_VERSION,
   380→      exportDate: new Date().toISOString(),
   381→      appVersion: APP_VERSION,
   382→      compressed: true,
   383→      data: parsedData,
   384→    };
   385→
   386→    // Optimize for compression (sorts keys, removes empty values)
   387→    const optimizedBackup = optimizeForCompression(backup);
   388→    const jsonString = JSON.stringify(optimizedBackup);
   389→    const compressedBlob = await compressData(jsonString);
   390→
   391→    // 1. Write/overwrite main file with custom filename
   392→    const mainFileHandle = await directoryHandle.getFileHandle(customFilename, { create: true });
   393→    const mainWritable = await mainFileHandle.createWritable();
   394→    await mainWritable.write(compressedBlob);
   395→    await mainWritable.close();
   396→
   397→    log.info('Main file saved', { filename: customFilename });
   398→
   399→    // 2. Create hidden .neuman-backups folder for versioning
   400→    const backupFolderHandle = await directoryHandle.getDirectoryHandle('.neuman-backups', { create: true });
   401→
   402→    // 3. Save versioned backup with timestamp
   403→    const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, -5);
   404→    const versionFilename = `backup-${timestamp}.brain`;
   405→    const versionFileHandle = await backupFolderHandle.getFileHandle(versionFilename, { create: true });
   406→    const versionWritable = await versionFileHandle.createWritable();
   407→    await versionWritable.write(compressedBlob);
   408→    await versionWritable.close();
   409→
   410→    log.debug('Version saved', { path: `.neuman-backups/${versionFilename}` });
   411→
   412→    // 4. Auto-cleanup old versions
   413→    try {
   414→      const versions: { name: string; timestamp: number }[] = [];
   415→      // @ts-ignore - TypeScript doesn't have proper types for FileSystemDirectoryHandle iteration
   416→      for await (const entry of backupFolderHandle.values()) {
   417→        if (entry.kind === 'file' && entry.name.startsWith('backup-') && entry.name.endsWith('.brain')) {
   418→          // Extract timestamp from filename
   419→          const file = await entry.getFile();
   420→          versions.push({
   421→            name: entry.name,
   422→            timestamp: file.lastModified,
   423→          });
   424→        }
   425→      }
   426→
   427→      // Sort by timestamp (newest first)
   428→      versions.sort((a, b) => b.timestamp - a.timestamp);
   429→
   430→      // Delete versions beyond the keep count
   431→      if (versions.length > versionCount) {
   432→        const toDelete = versions.slice(versionCount);
   433→        for (const old of toDelete) {
   434→          await backupFolderHandle.removeEntry(old.name);
   435→          log.debug('Deleted old version', { name: old.name });
   436→        }
   437→      }
   438→    } catch (cleanupError) {
   439→      log.warn('Failed to cleanup old versions', { error: cleanupError });
   440→      // Don't fail the entire save if cleanup fails
   441→    }
   442→
   443→    log.info('Auto-save complete', { filename: customFilename, versionsKept: versionCount });
   444→
   445→    return {
   446→      filename: customFilename,
   447→      size: compressedBlob.size,
   448→      compressed: true,
   449→    };
   450→  } catch (error) {
   451→    log.error('Auto-save failed', { error });
   452→    throw new Error(`Auto-save failed: ${error}`);
   453→  }
   454→};
   455→
   456→/**
   457→ * Check if File System Access API is supported
   458→ */
   459→export const isFileSystemAccessSupported = (): boolean => {
   460→  return 'showDirectoryPicker' in window;
   461→};
   462→
   463→/**
   464→ * Request directory access for auto-save
   465→ */
   466→export const requestAutoSaveDirectory = async (): Promise<FileSystemDirectoryHandle> => {
   467→  if (!isFileSystemAccessSupported()) {
   468→    throw new Error('File System Access API not supported in this browser');
   469→  }
   470→
   471→  if (!window.showDirectoryPicker) {
   472→    throw new Error('Directory picker not available');
   473→  }
   474→
   475→  try {
   476→    const dirHandle = await window.showDirectoryPicker({
   477→      mode: 'readwrite',
   478→    });
   479→    return dirHandle;
   480→  } catch (error) {
   481→    if ((error as Error).name === 'AbortError') {
   482→      throw new Error('Directory selection cancelled');
   483→    }
   484→    throw error;
   485→  }
   486→};
   487→
   488→/**
   489→ * Save directory handle to IndexedDB for persistence
   490→ * Browser can store FileSystemDirectoryHandle directly in IndexedDB
   491→ */
   492→export const saveDirectoryHandle = async (
   493→  handle: FileSystemDirectoryHandle
   494→): Promise<void> => {
   495→  try {
   496→    // Store the handle object directly (IndexedDB supports structured clones)
   497→    await indexedDBService.setObject('auto-save-directory-handle-obj', handle);
   498→    log.info('Directory handle saved to IndexedDB');
   499→  } catch (error) {
   500→    log.error('Failed to save directory handle', { error });
   501→    throw new Error(`Failed to save directory handle: ${error}`);
   502→  }
   503→};
   504→
   505→/**
   506→ * Retrieve directory handle from IndexedDB
   507→ * Verifies permissions and re-requests if needed
   508→ */
   509→export const getDirectoryHandle = async (): Promise<FileSystemDirectoryHandle | null> => {
   510→  try {
   511→    // Retrieve handle from IndexedDB
   512→    const handle = await indexedDBService.getObject<FileSystemDirectoryHandle>('auto-save-directory-handle-obj');
   513→
   514→    if (!handle) {
   515→      log.debug('No saved directory handle found');
   516→      return null;
   517→    }
   518→
   519→    // Verify permission (TypeScript type definitions may be incomplete)
   520→    const permission = await (handle as any).queryPermission({ mode: 'readwrite' });
   521→
   522→    if (permission === 'granted') {
   523→      log.info('Restored directory handle with granted permission');
   524→      return handle;
   525→    }
   526→
   527→    // Permission not granted, try to request it
   528→    log.debug('Permission not granted, requesting');
   529→    const newPermission = await (handle as any).requestPermission({ mode: 'readwrite' });
   530→
   531→    if (newPermission === 'granted') {
   532→      log.info('Permission granted after request');
   533→      return handle;
   534→    }
   535→
   536→    // Permission denied
   537→    log.warn('Permission denied for saved directory');
   538→    return null;
   539→  } catch (error) {
   540→    log.error('Failed to restore directory handle', { error });
   541→    return null;
   542→  }
   543→};
