// Add to existing indexedDBService class:

/**
 * Save project files to IndexedDB
 * Stored under key: phantom-project-{id}
 */
async saveProject(projectId: string, files: FileSystemTree): Promise<void> {
  const key = `phantom-project-${projectId}`;
  await this.setItem(key, JSON.stringify(files));
  log.debug('Project saved', { projectId });
}

/**
 * Load project files from IndexedDB
 */
async loadProject(projectId: string): Promise<FileSystemTree | null> {
  const key = `phantom-project-${projectId}`;
  const data = await this.getItem(key);
  if (!data) return null;
  return JSON.parse(data);
}

/**
 * Delete project files from IndexedDB
 */
async deleteProject(projectId: string): Promise<void> {
  const key = `phantom-project-${projectId}`;
  await this.removeItem(key);
  log.debug('Project deleted', { projectId });
}

/**
 * List all project IDs
 */
async listProjects(): Promise<string[]> {
  const allKeys = await this.getAllKeys();
  return allKeys
    .filter(key => key.startsWith('phantom-project-'))
    .map(key => key.replace('phantom-project-', ''));
}
