```typescript
/**
 * Preview Pane Component
 *
 * Shows running dev server output in an iframe.
 * Handles WebContainer server-ready events.
 *
 * Cross-Origin Note:
 * Because we use COEP/COOP headers, the iframe needs special handling.
 * WebContainer provides a same-origin URL that works with isolation.
 */

import React, { useEffect, useState } from 'react';
import { usePhantomShellStore } from '../../stores/usePhantomShellStore';

interface PreviewProps {
  className?: string;
}

export const Preview: React.FC<PreviewProps> = ({ className = '' }) => {
  const { devServerUrl, isDevServerRunning, showPreview } = usePhantomShellStore();
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (devServerUrl) {
      setIsLoading(true);
      setError(null);
    }
  }, [devServerUrl]);

  const handleLoad = () => {
    setIsLoading(false);
  };

  const handleError = () => {
    setError('Failed to load preview');
    setIsLoading(false);
  };

  if (!showPreview) {
    return null;
  }

  if (!isDevServerRunning || !devServerUrl) {
    return (
      <div className={`flex items-center justify-center bg-surface-dark ${className}`}>
        <div className="text-center text-text-muted">
          <div className="text-4xl mb-4">🚀</div>
          <p className="text-sm">No dev server running</p>
          <p className="text-xs mt-2 text-text-muted">
            Run <code className="text-accent-magenta">npm run dev</code> to start
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className={`relative bg-white ${className}`}>
      {/* Loading overlay */}
      {isLoading && (
        <div className="absolute inset-0 flex items-center justify-center bg-surface-dark z-10">
          <div className="flex flex-col items-center">
            <div className="animate-spin w-8 h-8 border-2 border-accent-magenta border-t-transparent rounded-full" />
            <p className="mt-4 text-sm text-text-muted">Loading preview...</p>
          </div>
        </div>
      )}

      {/* Error state */}
      {error && (
        <div className="absolute inset-0 flex items-center justify-center bg-surface-dark z-10">
          <div className="text-center">
            <div className="text-4xl mb-4">⚠️</div>
            <p className="text-red-400">{error}</p>
          </div>
        </div>
      )}

      {/* Iframe */}
      <iframe
        src={devServerUrl}
        className="w-full h-full border-0"
        onLoad={handleLoad}
        onError={handleError}
        title="Preview"
        sandbox="allow-scripts allow-same-origin allow-forms allow-modals allow-popups"
      />

      {/* URL bar */}
      <div className="absolute top-0 left-0 right-0 bg-surface-dark/90 backdrop-blur-sm px-3 py-1.5 flex items-center gap-2 border-b border-border-dark">
        <div className="w-2 h-2 rounded-full bg-green-500" />
        <span className="text-xs text-text-muted font-mono truncate flex-1">
          {devServerUrl}
        </span>
        <button
          onClick={() => window.open(devServerUrl, '_blank')}
          className="text-xs text-accent-cyan hover:underline"
        >
          Open ↗
        </button>
      </div>
    </div>
  );
};

export default Preview;
```

