   380→  output?: string;
   381→  exitCode?: number;
   382→}
   383→
   384→export interface PhantomShellState {
   385→  // Terminal
   386→  terminalInstance: XTerm | null;
   387→  isTerminalReady: boolean;
   388→
   389→  // WebContainer
   390→  webcontainer: WebContainer | null;
   391→  isWebContainerReady: boolean;
   392→  isWebContainerBooting: boolean;
   393→  webContainerError: string | null;
   394→
   395→  // Projects
   396→  projects: Record<string, PhantomProject>;
   397→  activeProjectId: string | null;
   398→
   399→  // Command History
   400→  commandHistory: CommandHistoryEntry[];
   401→  historyIndex: number;
   402→
   403→  // Dev Server
   404→  devServerUrl: string | null;
   405→  devServerPort: number | null;
   406→  isDevServerRunning: boolean;
   407→
   408→  // UI State
   409→  isPanelOpen: boolean;
   410→  showPreview: boolean;
   411→  splitRatio: number;  // 0-100, percentage for terminal vs preview
   412→
   413→  // AI Integration
   414→  isAIProcessing: boolean;
   415→  lastAICommand: string | null;
   416→}
   417→
   418→export interface PhantomShellActions {
   419→  // Terminal
   420→  setTerminalInstance: (terminal: XTerm | null) => void;
   421→  setTerminalReady: (ready: boolean) => void;
   422→  writeToTerminal: (data: string) => void;
   423→  clearTerminal: () => void;
   424→
   425→  // WebContainer
   426→  setWebContainer: (container: WebContainer | null) => void;
   427→  setWebContainerReady: (ready: boolean) => void;
   428→  setWebContainerBooting: (booting: boolean) => void;
   429→  setWebContainerError: (error: string | null) => void;
   430→
   431→  // Projects
   432→  createProject: (project: Omit<PhantomProject, 'id' | 'createdAt' | 'updatedAt'>) => string;
   433→  updateProject: (id: string, updates: Partial<PhantomProject>) => void;
   434→  deleteProject: (id: string) => void;
   435→  setActiveProject: (id: string | null) => void;
   436→
   437→  // Command History
   438→  addToHistory: (entry: Omit<CommandHistoryEntry, 'timestamp'>) => void;
