   704→export interface ShellContext {
   705→  terminal: { clear: () => void; write: (data: string) => void } | null;
   706→  webcontainer: WebContainer | null;
   707→  activeProjectId: string | null;
   708→  getHistory: () => { command: string; timestamp: string }[];
   709→  getProjects: () => { id: string; name: string; metadata: { framework?: string } }[];
   710→  createProject: (name: string) => string;
   711→}
   712→
   713→// Built-in commands that don't require WebContainer
   714→const BUILTIN_COMMANDS = new Set([
   715→  'help', 'clear', 'history', 'projects', 'new', 'open', 'close',
   716→  'export', 'import', 'theme', 'version', 'about',
   717→]);
   718→
   719→// ==================== COMMAND PARSER ====================
   720→
   721→export const parseCommand = (input: string): ShellCommand => {
   722→  const trimmed = input.trim();
   723→
   724→  // Check for AI command
   725→  if (trimmed.startsWith('/ai ') || trimmed === '/ai') {
   726→    return {
   727→      type: 'ai',
   728→      name: 'ai',
   729→      args: trimmed.slice(4).trim().split(/\s+/).filter(Boolean),
   730→      raw: trimmed,
   731→    };
   732→  }
   733→
   734→  // Check for builtin command (starts with /)
   735→  if (trimmed.startsWith('/')) {
   736→    const parts = trimmed.slice(1).split(/\s+/);
   737→    const name = parts[0]?.toLowerCase() || '';
   738→
   739→    if (BUILTIN_COMMANDS.has(name)) {
   740→      return {
   741→        type: 'builtin',
   742→        name,
   743→        args: parts.slice(1),
   744→        raw: trimmed,
   745→      };
   746→    }
   747→  }
   748→
   749→  // System command (npm, node, etc.)
   750→  const parts = trimmed.split(/\s+/);
   751→  return {
   752→    type: 'system',
   753→    name: parts[0] || '',
   754→    args: parts.slice(1),
   755→    raw: trimmed,
   756→  };
   757→};
   758→
   759→// ==================== BUILTIN COMMAND HANDLERS ====================
   760→
   761→export const builtinHandlers: Record<string, (args: string[], context: ShellContext) => string> = {
   762→  help: () => `
   763→\x1b[1;36mPhantom Shell Commands\x1b[0m
   764→
   765→\x1b[33mBuilt-in Commands:\x1b[0m
   766→  /help              Show this help message
   767→  /clear             Clear terminal screen
   768→  /history           Show command history
   769→  /version           Show version info
   770→
   771→\x1b[33mProject Commands:\x1b[0m
   772→  /projects          List all projects
   773→  /new <name>        Create new project
   774→  /open <name>       Open existing project
   775→  /close             Close current project
   776→  /export            Export project to .brain file
   777→
   778→\x1b[33mAI Commands:\x1b[0m
   779→  /ai <prompt>       Ask AI to help (e.g., /ai create a react app)
   780→
   781→\x1b[33mSystem Commands:\x1b[0m
   782→  npm, node, npx     Standard Node.js commands
   783→  ls, cd, cat, etc.  File system commands
   784→`,
   785→
   786→  clear: (_args, context) => {
   787→    context.terminal?.clear();
   788→    return '';
   789→  },
   790→
   791→  history: (_args, context) => {
   792→    const history = context.getHistory();
   793→    if (history.length === 0) {
   794→      return '\x1b[90mNo command history\x1b[0m';
   795→    }
   796→    return history
   797→      .slice(-20)
   798→      .map((entry, i) => `\x1b[90m${i + 1}.\x1b[0m ${entry.command}`)
   799→      .join('\n');
   800→  },
   801→
   802→  version: () => `
   803→\x1b[1;35mPhantom Shell\x1b[0m v1.0.0
   804→\x1b[90mNeuman Brain Dashboard\x1b[0m v2.0.0
   805→\x1b[90mWebContainer API\x1b[0m v1.5.1
   806→\x1b[90mxterm.js\x1b[0m v5.5.0
   807→`,
   808→
   809→  projects: (_args, context) => {
   810→    const projects = context.getProjects();
   811→    if (projects.length === 0) {
   812→      return '\x1b[90mNo projects yet. Use \x1b[33m/new <name>\x1b[90m to create one.\x1b[0m';
   813→    }
   814→
   815→    return projects
   816→      .map(p => {
   817→        const active = context.activeProjectId === p.id ? '\x1b[32m● \x1b[0m' : '  ';
   818→        const framework = p.metadata.framework ? `\x1b[90m[${p.metadata.framework}]\x1b[0m` : '';
   819→        return `${active}\x1b[36m${p.name}\x1b[0m ${framework}`;
   820→      })
   821→      .join('\n');
   822→  },
   823→
   824→  new: (args, context) => {
   825→    const name = args.join(' ').trim();
   826→    if (!name) {
   827→      return '\x1b[31mError: Project name required\x1b[0m\nUsage: /new <project-name>';
   828→    }
   829→
   830→    // Validate name
   831→    if (!/^[a-zA-Z0-9_-]+$/.test(name)) {
   832→      return '\x1b[31mError: Invalid project name\x1b[0m\nUse only letters, numbers, hyphens, and underscores.';
   833→    }
   834→
   835→    const id = context.createProject(name);
   836→    return `\x1b[32m✓ Created project:\x1b[0m ${name}\n\x1b[90mProject ID: ${id}\x1b[0m`;
   837→  },
   838→
   839→  about: () => `
   840→\x1b[1;35m╔══════════════════════════════════════════════════════════╗
   841→║                    PHANTOM SHELL                           ║
   842→╚══════════════════════════════════════════════════════════╝\x1b[0m
   843→
   844→A browser-native development environment that runs entirely
   845→in your browser. No installation, no servers, no cloud.
   846→
   847→\x1b[36mFeatures:\x1b[0m
   848→  • Full Node.js runtime in browser (via WebContainers)
   849→  • Real terminal emulator (xterm.js)
   850→  • AI-assisted development (/ai commands)
   851→  • Project persistence (IndexedDB)
   852→  • Export to .brain files
   853→
   854→\x1b[90mBuilt for Neuman Brain Dashboard\x1b[0m
   855→\x1b[90mPrivacy-first • Zero data collection\x1b[0m
   856→`,
   857→};
   858→
   859→// ==================== COMMAND EXECUTOR ====================
   860→
   861→export class ShellExecutor {
   862→  private webcontainer: WebContainer | null = null;
   863→  private currentProcess: WebContainerProcess | null = null;
   864→
   865→  setWebContainer(container: WebContainer | null) {
   866→    this.webcontainer = container;
   867→  }
   868→
   869→  async executeBuiltin(
   870→    command: ShellCommand,
   871→    context: ShellContext
   872→  ): Promise<string> {
   873→    const handler = builtinHandlers[command.name];
   874→    if (!handler) {
   875→      return `\x1b[31mUnknown command: /${command.name}\x1b[0m\nType /help for available commands.`;
   876→    }
   877→    return handler(command.args, context);
   878→  }
   879→
   880→  async executeSystem(
   881→    command: ShellCommand,
   882→    onStdout: (data: string) => void,
   883→    onStderr: (data: string) => void,
   884→  ): Promise<number> {
   885→    if (!this.webcontainer) {
   886→      onStderr('\x1b[31mError: WebContainer not initialized\x1b[0m\n');
   887→      onStderr('\x1b[90mHint: WebContainer is still booting. Please wait...\x1b[0m\n');
   888→      return 1;
   889→    }
   890→
   891→    log.info('Executing system command', { command: command.raw });
   892→
   893→    try {
   894→      // Spawn process in WebContainer
   895→      const process = await this.webcontainer.spawn(command.name, command.args);
   896→      this.currentProcess = process;
   897→
   898→      // Stream stdout
   899→      process.output.pipeTo(new WritableStream({
   900→        write(data) {
   901→          onStdout(data);
   902→        }
   903→      }));
   904→
   905→      // Wait for exit
   906→      const exitCode = await process.exit;
   907→      this.currentProcess = null;
   908→
   909→      log.debug('Command completed', { command: command.name, exitCode });
   910→      return exitCode;
   911→    } catch (error) {
   912→      log.error('Command execution failed', { command: command.raw, error });
   913→      onStderr(`\x1b[31mError: ${error}\x1b[0m\n`);
   914→      return 1;
   915→    }
   916→  }
   917→
   918→  kill() {
   919→    if (this.currentProcess) {
   920→      this.currentProcess.kill();
   921→      this.currentProcess = null;
   922→    }
   923→  }
   924→}
   925→
   926→export const shellExecutor = new ShellExecutor();
   927→```
