  1059→#### 2.1 WebContainer Service
  1060→
  1061→**File:** `src/services/phantomShell/webContainerService.ts`
  1062→
  1063→```typescript
  1064→/**
  1065→ * WebContainer Service
  1066→ *
  1067→ * Manages WebContainer lifecycle:
  1068→ * - Boot/teardown
  1069→ * - File system operations
  1070→ * - Process spawning
  1071→ * - Dev server management
  1072→ *
  1073→ * WebContainer runs a full Node.js environment in the browser
  1074→ * using WebAssembly. Requires Cross-Origin Isolation headers.
  1075→ */
  1076→
  1077→import { WebContainer, type FileSystemTree } from '@webcontainer/api';
  1078→import { logger } from '../logger';
  1079→import { usePhantomShellStore } from '../../stores/usePhantomShellStore';
  1080→
  1081→const log = logger.module('PhantomShell:WebContainer');
  1082→
  1083→// Singleton instance
  1084→let webcontainerInstance: WebContainer | null = null;
  1085→let bootPromise: Promise<WebContainer> | null = null;
  1086→
  1087→// ==================== BOOT ====================
  1088→
  1089→/**
  1090→ * Boot WebContainer instance (singleton)
  1091→ *
  1092→ * This is an expensive operation (~2-5 seconds) so we:
  1093→ * 1. Only boot once per session
  1094→ * 2. Reuse the same instance
  1095→ * 3. Show loading state to user
  1096→ */
  1097→export const bootWebContainer = async (): Promise<WebContainer> => {
  1098→  // Return existing instance
  1099→  if (webcontainerInstance) {
  1100→    log.debug('Returning existing WebContainer instance');
  1101→    return webcontainerInstance;
  1102→  }
  1103→
  1104→  // Return pending boot
  1105→  if (bootPromise) {
  1106→    log.debug('Waiting for pending WebContainer boot');
  1107→    return bootPromise;
  1108→  }
  1109→
  1110→  // Check for Cross-Origin Isolation
  1111→  if (!crossOriginIsolated) {
  1112→    const error = 'WebContainer requires Cross-Origin Isolation. ' +
  1113→      'Ensure COEP and COOP headers are set in vite.config.ts and public/_headers';
  1114→    log.error(error);
  1115→    usePhantomShellStore.getState().setWebContainerError(error);
  1116→    throw new Error(error);
  1117→  }
  1118→
  1119→  // Start boot process
  1120→  log.info('Booting WebContainer...');
  1121→  usePhantomShellStore.getState().setWebContainerBooting(true);
  1122→
  1123→  bootPromise = WebContainer.boot()
  1124→    .then((instance) => {
  1125→      webcontainerInstance = instance;
  1126→      usePhantomShellStore.getState().setWebContainer(instance);
  1127→      usePhantomShellStore.getState().setWebContainerReady(true);
  1128→      usePhantomShellStore.getState().setWebContainerBooting(false);
  1129→
  1130→      log.info('WebContainer booted successfully');
  1131→
  1132→      // Set up server-ready listener for dev servers
  1133→      instance.on('server-ready', (port, url) => {
  1134→        log.info('Dev server ready', { port, url });
  1135→        usePhantomShellStore.getState().setDevServer(url, port);
  1136→        usePhantomShellStore.getState().setDevServerRunning(true);
  1137→      });
  1138→
  1139→      return instance;
  1140→    })
  1141→    .catch((error) => {
  1142→      log.error('WebContainer boot failed', { error });
  1143→      usePhantomShellStore.getState().setWebContainerError(String(error));
  1144→      usePhantomShellStore.getState().setWebContainerBooting(false);
  1145→      bootPromise = null;
  1146→      throw error;
  1147→    });
  1148→
  1149→  return bootPromise;
  1150→};
  1151→
  1152→// ==================== FILE SYSTEM ====================
  1153→
  1154→/**
  1155→ * Mount a file system tree to WebContainer
  1156→ */
  1157→export const mountFileSystem = async (
  1158→  files: FileSystemTree,
  1159→  path: string = '/'
  1160→): Promise<void> => {
  1161→  const container = await bootWebContainer();
  1162→  log.debug('Mounting file system', { path, fileCount: Object.keys(files).length });
  1163→  await container.mount(files, { mountPoint: path });
  1164→  log.info('File system mounted', { path });
  1165→};
  1166→
  1167→/**
  1168→ * Read a file from WebContainer
  1169→ */
  1170→export const readFile = async (path: string): Promise<string> => {
  1171→  const container = await bootWebContainer();
  1172→  return container.fs.readFile(path, 'utf-8');
  1173→};
  1174→
  1175→/**
  1176→ * Write a file to WebContainer
  1177→ */
  1178→export const writeFile = async (path: string, contents: string): Promise<void> => {
  1179→  const container = await bootWebContainer();
  1180→  await container.fs.writeFile(path, contents);
  1181→  log.debug('File written', { path, size: contents.length });
  1182→};
