  1184→/**
  1185→ * Create directory in WebContainer
  1186→ */
  1187→export const mkdir = async (path: string, recursive: boolean = true): Promise<void> => {
  1188→  const container = await bootWebContainer();
  1189→  await container.fs.mkdir(path, { recursive });
  1190→  log.debug('Directory created', { path });
  1191→};
  1192→
  1193→/**
  1194→ * List directory contents
  1195→ */
  1196→export const readdir = async (path: string): Promise<string[]> => {
  1197→  const container = await bootWebContainer();
  1198→  return container.fs.readdir(path);
  1199→};
  1200→
  1201→/**
  1202→ * Remove file or directory
  1203→ */
  1204→export const rm = async (path: string, recursive: boolean = false): Promise<void> => {
  1205→  const container = await bootWebContainer();
  1206→  await container.fs.rm(path, { recursive });
  1207→  log.debug('Removed', { path, recursive });
  1208→};
  1209→
  1210→// ==================== PROCESS MANAGEMENT ====================
  1211→
  1212→/**
  1213→ * Spawn a process in WebContainer
  1214→ */
  1215→export const spawn = async (
  1216→  command: string,
  1217→  args: string[],
  1218→  options?: { cwd?: string; env?: Record<string, string> }
  1219→) => {
