  1328→    },
  1329→  },
  1330→};
  1331→
  1332→/**
  1333→ * Create project from template
  1334→ */
  1335→export const createProjectFromTemplate = async (
  1336→  projectName: string,
  1337→  template: keyof typeof PROJECT_TEMPLATES
  1338→): Promise<void> => {
  1339→  const files = PROJECT_TEMPLATES[template];
  1340→  if (!files) {
  1341→    throw new Error(`Unknown template: ${template}`);
  1342→  }
  1343→
  1344→  // Update package.json with project name
  1345→  const pkgJson = files['package.json'];
  1346→  if (pkgJson && 'file' in pkgJson) {
  1347→    const pkg = JSON.parse(pkgJson.file.contents);
  1348→    pkg.name = projectName;
  1349→    pkgJson.file.contents = JSON.stringify(pkg, null, 2);
  1350→  }
  1351→
  1352→  await mountFileSystem(files);
  1353→  log.info('Project created from template', { projectName, template });
  1354→};
