/**
 * PhantomShell Terminal Component
 *
 * Real terminal emulator using xterm.js with full keyboard support,
 * command history, and visual styling matching the Neuman Brain theme.
 *
 * Features:
 * - Full ANSI color support
 * - Command history (up/down arrows)
 * - Copy/paste support
 * - Auto-resize on container change
 * - Clickable URLs
 * - Find functionality (Ctrl+Shift+F)
 */

import React, { useEffect, useRef, useCallback } from 'react';
import { Terminal as XTerm } from '@xterm/xterm';
import { FitAddon } from '@xterm/addon-fit';
import { WebLinksAddon } from '@xterm/addon-web-links';
import { SearchAddon } from '@xterm/addon-search';
import '@xterm/xterm/css/xterm.css';
import { usePhantomShellStore } from '../../stores/usePhantomShellStore';
import { logger } from '../../services/logger';

const log = logger.module('PhantomShell:Terminal');

// Neuman Brain theme colors mapped to xterm
const THEME = {
  background: '#0a0a0f',           // Dark surface
  foreground: '#e4e4e7',           // Light text
  cursor: '#d946ef',               // Magenta accent
  cursorAccent: '#0a0a0f',
  selectionBackground: '#3b0764',  // Purple selection
  selectionForeground: '#e4e4e7',
  // ANSI colors
  black: '#18181b',
  red: '#ef4444',
  green: '#22c55e',
  yellow: '#eab308',
  blue: '#3b82f6',
  magenta: '#d946ef',              // Primary accent
  cyan: '#06b6d4',                 // Secondary accent
  white: '#e4e4e7',
  brightBlack: '#71717a',
  brightRed: '#f87171',
  brightGreen: '#4ade80',
  brightYellow: '#facc15',
  brightBlue: '#60a5fa',
  brightMagenta: '#e879f9',
  brightCyan: '#22d3ee',
  brightWhite: '#fafafa',
};

interface TerminalProps {
  onData?: (data: string) => void;
  onResize?: (cols: number, rows: number) => void;
}

export const Terminal: React.FC<TerminalProps> = ({ onData, onResize }) => {
  const terminalRef = useRef<HTMLDivElement>(null);
  const xtermRef = useRef<XTerm | null>(null);
  const fitAddonRef = useRef<FitAddon | null>(null);

  const { setTerminalInstance } = usePhantomShellStore();

  // Initialize terminal
  useEffect(() => {
    if (!terminalRef.current || xtermRef.current) return;

    log.info('Initializing xterm.js terminal');

    const xterm = new XTerm({
      theme: THEME,
      fontFamily: '"JetBrains Mono", "Fira Code", "Cascadia Code", Menlo, monospace',
      fontSize: 14,
      lineHeight: 1.2,
      cursorBlink: true,
      cursorStyle: 'block',
      scrollback: 10000,
      tabStopWidth: 4,
      allowProposedApi: true,
    });

    // Add fit addon for auto-resize
    const fitAddon = new FitAddon();
    xterm.loadAddon(fitAddon);
    fitAddonRef.current = fitAddon;

    // Add web links addon for clickable URLs
    const webLinksAddon = new WebLinksAddon();
    xterm.loadAddon(webLinksAddon);

    // Add search addon
    const searchAddon = new SearchAddon();
    xterm.loadAddon(searchAddon);

    // Open terminal in container
    xterm.open(terminalRef.current);
    fitAddon.fit();

    // Store reference
    xtermRef.current = xterm;
    setTerminalInstance(xterm);

    // Set up data handler
    if (onData) {
      xterm.onData(onData);
    }

    // Set up resize handler
    xterm.onResize(({ cols, rows }) => {
      log.debug('Terminal resized', { cols, rows });
      onResize?.(cols, rows);
    });

    // Initial welcome message
    xterm.writeln('\x1b[1;35m╔══════════════════════════════════════════╗\x1b[0m');
    xterm.writeln('\x1b[1;35m║\x1b[0m    \x1b[1;36mPhantom Shell\x1b[0m - Browser Native Dev    \x1b[1;35m║\x1b[0m');
    xterm.writeln('\x1b[1;35m╚══════════════════════════════════════════╝\x1b[0m');
    xterm.writeln('');
    xterm.writeln('\x1b[90mType \x1b[33m/help\x1b[90m for commands or \x1b[33m/ai\x1b[90m to chat with AI\x1b[0m');
    xterm.writeln('');

    log.info('Terminal initialized successfully');

    // Cleanup
    return () => {
      log.debug('Disposing terminal');
      xterm.dispose();
      xtermRef.current = null;
    };
  }, [onData, onResize, setTerminalInstance]);

  // Handle container resize
  useEffect(() => {
    const handleResize = () => {
      if (fitAddonRef.current && xtermRef.current) {
        fitAddonRef.current.fit();
      }
    };

    const resizeObserver = new ResizeObserver(handleResize);
    if (terminalRef.current) {
      resizeObserver.observe(terminalRef.current);
    }

    window.addEventListener('resize', handleResize);

    return () => {
      resizeObserver.disconnect();
      window.removeEventListener('resize', handleResize);
    };
  }, []);

  return (
    <div
      ref={terminalRef}
      className="w-full h-full min-h-[300px] bg-[#0a0a0f] rounded-lg overflow-hidden"
      style={{ padding: '8px' }}
    />
  );
};

export default Terminal;
```

