     1→/**
     2→ * Encryption Service for API Keys
     3→ * Uses WebCrypto API for AES-256-GCM encryption with PBKDF2 key derivation
     4→ * Provides secure, password-based encryption for sensitive data
     5→ *
     6→ * MIGRATION NOTE: This file now uses WebCrypto API instead of crypto-js
     7→ * - All functions are now async (use await)
     8→ * - Provides backward compatibility for old crypto-js encrypted data
     9→ */
    10→
    11→import * as WebCrypto from './encryptionWebCrypto';
    12→import CryptoJS from 'crypto-js'; // Keep for backward compatibility with old encrypted data
    13→
    14→/**
    15→ * Encryption configuration constants
    16→ */
    17→const ENCRYPTION_CONFIG = {
    18→  iterations: 100000, // PBKDF2 iterations (100k recommended minimum)
    19→  keySize: 256 / 32, // 256-bit key
    20→  algorithm: 'AES',
    21→};
    22→
    23→/**
    24→ * Encrypted data structure
    25→ */
    26→export interface EncryptedData {
    27→  ciphertext: string;
    28→  salt: string;
    29→  iv: string;
    30→  version?: 'crypto-js' | 'webcrypto'; // Track encryption method for migration
    31→}
    32→
    33→/**
    34→ * Derive encryption key from password using PBKDF2 (crypto-js - for backward compatibility)
    35→ * @param password - User's encryption password
    36→ * @param salt - Salt for key derivation
    37→ * @returns Derived encryption key
    38→ */
    39→function deriveKey(password: string, salt: string): CryptoJS.lib.WordArray {
    40→  return CryptoJS.PBKDF2(password, salt, {
    41→    keySize: ENCRYPTION_CONFIG.keySize,
    42→    iterations: ENCRYPTION_CONFIG.iterations,
    43→  });
    44→}
    45→
    46→/**
    47→ * Encrypt plaintext using AES-256-GCM (WebCrypto API)
    48→ * @param plaintext - Data to encrypt (e.g., API key)
    49→ * @param password - User's encryption password
    50→ * @returns Encrypted data with salt and IV
    51→ */
    52→export async function encrypt(plaintext: string, password: string): Promise<EncryptedData> {
    53→  const encrypted = await WebCrypto.encrypt(plaintext, password);
    54→  return {
    55→    ...encrypted,
    56→    version: 'webcrypto', // Mark as WebCrypto encrypted
    57→  };
    58→}
    59→
    60→/**
    61→ * Decrypt ciphertext using AES-256-GCM (WebCrypto) or AES-256-CBC (crypto-js for backward compatibility)
    62→ * @param encryptedData - Encrypted data with salt and IV
    63→ * @param password - User's encryption password
    64→ * @returns Decrypted plaintext
    65→ * @throws Error if decryption fails (wrong password or corrupted data)
    66→ */
    67→export async function decrypt(encryptedData: EncryptedData, password: string): Promise<string> {
    68→  if (!encryptedData || !password) {
    69→    throw new Error('Encrypted data and password are required for decryption');
    70→  }
    71→
    72→  const { ciphertext, salt, iv, version } = encryptedData;
    73→
    74→  if (!ciphertext || !salt || !iv) {
    75→    throw new Error('Invalid encrypted data structure');
    76→  }
    77→
    78→  // If encrypted with WebCrypto, use WebCrypto to decrypt
    79→  if (version === 'webcrypto') {
    80→    // Pass only the fields WebCrypto expects (exclude our library version marker)
    81→    return WebCrypto.decrypt({ ciphertext, salt, iv }, password);
    82→  }
    83→
    84→  // Otherwise, assume old crypto-js format (backward compatibility)
    85→  try {
    86→    // Derive the same encryption key from password and salt
    87→    const key = deriveKey(password, salt);
    88→
    89→    // Decrypt using AES-256-CBC (crypto-js)
    90→    const decrypted = CryptoJS.AES.decrypt(ciphertext, key, {
    91→      iv: CryptoJS.enc.Hex.parse(iv),
    92→      mode: CryptoJS.mode.CBC,
    93→      padding: CryptoJS.pad.Pkcs7,
    94→    });
    95→
    96→    // Convert decrypted WordArray to UTF-8 string
    97→    const plaintext = decrypted.toString(CryptoJS.enc.Utf8);
    98→
    99→    if (!plaintext) {
   100→      throw new Error('Decryption failed - invalid password or corrupted data');
   101→    }
   102→
   103→    return plaintext;
   104→  } catch (error) {
   105→    throw new Error(`Decryption failed: ${error instanceof Error ? error.message : 'Unknown error'}`);
   106→  }
   107→}
   108→
   109→/**
   110→ * Validate password strength
   111→ * @param password - Password to validate
   112→ * @returns Object with validation result and message
   113→ */
   114→export function validatePassword(password: string): { valid: boolean; message: string } {
   115→  if (!password || password.length < 8) {
   116→    return {
   117→      valid: false,
   118→      message: 'Password must be at least 8 characters long',
   119→    };
   120→  }
   121→
   122→  if (password.length > 128) {
   123→    return {
   124→      valid: false,
   125→      message: 'Password must be less than 128 characters',
   126→    };
   127→  }
   128→
   129→  // Check for at least one number, one letter
   130→  const hasNumber = /\d/.test(password);
   131→  const hasLetter = /[a-zA-Z]/.test(password);
   132→
   133→  if (!hasNumber || !hasLetter) {
   134→    return {
   135→      valid: false,
   136→      message: 'Password must contain at least one letter and one number',
   137→    };
   138→  }
   139→
   140→  return {
   141→    valid: true,
   142→    message: 'Password is strong',
   143→  };
   144→}
   145→
   146→/**
   147→ * Hash password for verification (not for encryption key derivation)
   148→ * Used to verify password without decrypting data
   149→ * @param password - Password to hash
   150→ * @returns Password hash
   151→ */
   152→export async function hashPassword(password: string): Promise<string> {
   153→  return WebCrypto.hashPassword(password);
   154→}
   155→
   156→/**
   157→ * Verify password against stored hash
   158→ * @param password - Password to verify
   159→ * @param hash - Stored password hash
   160→ * @returns True if password matches hash
   161→ */
   162→export async function verifyPassword(password: string, hash: string): Promise<boolean> {
   163→  return WebCrypto.verifyPassword(password, hash);
   164→}
   165→
   166→/**
   167→ * Calculate password expiry date
   168→ * @param duration - 'daily' | 'weekly' | 'monthly'
   169→ * @returns Date when password should expire
   170→ */
   171→export function calculatePasswordExpiry(duration: 'daily' | 'weekly' | 'monthly'): Date {
   172→  const now = new Date();
