   342→              <div className="mb-4 p-3 bg-yellow-100 dark:bg-yellow-900/30 border border-yellow-400 dark:border-yellow-600 rounded-button text-sm text-text-light-primary dark:text-text-dark-primary">
   343→                {fallbackNotification}
   344→              </div>
   345→            )}
   346→
   347→            {messages.length === 0 && router.getConfiguredProviders().length === 0 && (
   348→              <div className="text-center py-12 text-text-light-secondary dark:text-text-dark-secondary">
   349→                <p className="text-lg font-semibold mb-2">Welcome to AI Terminal!</p>
   350→                <p className="text-sm mb-4">
   351→                  Configure AI providers to get started. Choose from 8 providers including free options!
   352→                </p>
   353→                <button
   354→                  onClick={() => setShowProviderSettings(true)}
   355→                  className="px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button transition-all duration-standard ease-smooth"
   356→                >
   357→                  ⚙️ Configure Providers
   358→                </button>
   359→                <div className="mt-4 text-xs space-y-1">
   360→                  <p className="font-medium">Free Providers Available:</p>
   361→                  <p>• OpenRouter (Llama 3.3, Gemini 2.0)</p>
