   363→                  <p>• HuggingFace (Thousands of models)</p>
   364→                  <p>• Mistral (European AI)</p>
   365→                </div>
   366→              </div>
   367→            )}
   368→
   369→            {messages.length === 0 && router.getConfiguredProviders().length > 0 && (
   370→              <div className="text-center py-12 text-text-light-secondary dark:text-text-dark-secondary">
   371→                <p className="text-lg font-semibold mb-2">AI Terminal Ready</p>
   372→                <p className="text-sm mb-2">
