                <div
                  key={providerId}
                  className="p-4 bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button"
                >
                  {/* Provider Header */}
                  <div className="flex items-start justify-between mb-3">
                    <div className="flex-1">
                      <div className="flex items-center gap-2 mb-1">
                        <h3 className="font-medium text-text-light-primary dark:text-text-dark-primary">
                          {metadata.displayName}
