                  <div className="space-y-2">
                    <div className="flex gap-2">
                      <div className="flex-1 relative">
                        <input
                          type={showApiKeys[providerId] ? 'text' : 'password'}
                          value={apiKeyInputs[providerId] || ''}
                          onChange={(e) =>
                            setApiKeyInputs((prev) => ({ ...prev, [providerId]: e.target.value }))
                          }
                          placeholder={
