                              ? 'Enter new API key to replace existing'
                              : `Enter your ${metadata.apiKeyLabel || 'API key'}`
                          }
                          className="w-full px-3 py-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-blue text-text-light-primary dark:text-text-dark-primary text-sm"
                        />
                        <button
                          type="button"
                          onClick={() => toggleShowApiKey(providerId)}
                          className="absolute right-2 top-1/2 -translate-y-1/2 text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary text-xs"
                        >
                          {showApiKeys[providerId] ? 'Hide' : 'Show'}
                        </button>
                      </div>
                    </div>

                    {/* Action Buttons */}
                    <div className="flex gap-2">
                      <button
                        onClick={() => handleSaveApiKey(providerId)}
                        disabled={!apiKeyInputs[providerId]?.trim()}
                        className="px-3 py-1.5 bg-accent-blue hover:bg-accent-blue-hover disabled:bg-slate-500/20 disabled:text-slate-500 disabled:cursor-not-allowed text-white rounded-buttontext-sm transition-all duration-standard ease-smooth"
                      >
                        {isConfigured ? 'Update' : 'Save'}
                      </button>

                      <button
                        onClick={() => handleTestApiKey(providerId)}
                        disabled={!apiKeyInputs[providerId]?.trim() || validating[providerId]}
                        className="px-3 py-1.5 bg-surface-light-elevated dark:bg-surface-dark-elevated hover:bg-surface-light dark:hover:bg-neutral-800 disabled:opacity-50 disabled:cursor-not-allowed border border-border-light dark:border-border-dark rounded-buttontext-sm text-text-light-primary dark:text-text-dark-primary transition-all duration-standard ease-smooth"
                      >
                        {validating[providerId] ? 'Testing...' : 'Test Key'}
                      </button>

                      {isConfigured && (
                        <button
                          onClick={() => handleClearApiKey(providerId)}
                          className="px-3 py-1.5 bg-red-500/10 hover:bg-red-500/20 border border-red-500/20 rounded-buttontext-sm text-red-500 transition-all duration-standard ease-smooth"
                        >
                          Remove
                        </button>
                      )}

                      {/* Validation Result */}
                      {validationResults[providerId] !== null && (
                        <span
                          className={`px-2 py-1.5 text-xs rounded-button${
                            validationResults[providerId]
                              ? 'bg-green-500/10 text-green-500'
