                          }`}
                        >
                          {validationResults[providerId] ? '✓ Valid' : '✗ Invalid'}
                        </span>
                      )}
                    </div>
                  </div>
                </div>
              );
            })}
          </div>

          {/* Footer Actions */}
          <div className="flex justify-end pt-4 border-t border-border-light dark:border-border-dark">
            <button
              onClick={onClose}
              className="px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button transition-all duration-standard ease-smooth"
            >
              Done
            </button>
          </div>
        </div>
      </Modal>

      {/* Password Prompt Modal */}
      <PasswordPrompt
        isOpen={showPasswordPrompt}
        onSubmit={handlePasswordSubmit}
        onCancel={() => {
          setShowPasswordPrompt(false);
          setSelectedProvider(null);
        }}
        mode={passwordHash ? 'unlock' : 'setup'}
        existingPasswordHash={passwordHash || undefined}
      />
    </>
  );
}

