     1→/**
     2→ * Usage Tracker Component
     3→ * Track AI provider usage (requests, tokens, costs)
     4→ *
     5→ * Features:
     6→ * - Per-provider request counting
     7→ * - Token usage tracking (prompt + completion)
     8→ * - Cost estimation for paid providers
     9→ * - Visual usage charts
    10→ * - Export usage data
    11→ * - Reset tracking
    12→ */
    13→
    14→import { useState, useMemo } from 'react';
    15→import { useTerminalStore, type Message } from '../stores/useTerminalStore';
    16→import { AIProviderRouter } from '../services/ai/providerRouter';
    17→
    18→interface UsageTrackerProps {
    19→  router: AIProviderRouter;
    20→}
    21→
    22→interface ProviderUsage {
    23→  providerId: string;
    24→  providerName: string;
    25→  requestCount: number;
    26→  totalTokens: number;
    27→  promptTokens: number;
    28→  completionTokens: number;
    29→  estimatedCost: number;
    30→  lastUsed: number | null;
    31→}
    32→
    33→export function UsageTracker({ router }: UsageTrackerProps) {
    34→  const messages = useTerminalStore((state) => state.messages);
    35→  const [timeRange, setTimeRange] = useState<'today' | 'week' | 'month' | 'all'>('week');
    36→
    37→  // Calculate usage statistics from messages
    38→  const usageStats = useMemo(() => {
    39→    const now = Date.now();
    40→    const cutoffTimes = {
    41→      today: now - 24 * 60 * 60 * 1000,
    42→      week: now - 7 * 24 * 60 * 60 * 1000,
    43→      month: now - 30 * 24 * 60 * 60 * 1000,
    44→      all: 0,
    45→    };
    46→
    47→    const cutoff = cutoffTimes[timeRange];
    48→    const filteredMessages = messages.filter((msg) => msg.timestamp >= cutoff);
    49→
    50→    // Group by provider
    51→    const providerStats: Record<string, ProviderUsage> = {};
    52→
    53→    filteredMessages.forEach((msg: Message) => {
    54→      if (!msg.provider) return; // Skip messages without provider info
    55→
    56→      if (!providerStats[msg.provider]) {
    57→        const provider = router.getProvider(msg.provider);
    58→        providerStats[msg.provider] = {
    59→          providerId: msg.provider,
    60→          providerName: provider?.metadata.displayName || msg.provider,
    61→          requestCount: 0,
    62→          totalTokens: 0,
    63→          promptTokens: 0,
    64→          completionTokens: 0,
    65→          estimatedCost: 0,
    66→          lastUsed: null,
    67→        };
    68→      }
    69→
    70→      const stats = providerStats[msg.provider];
    71→
    72→      // Count assistant messages as requests
    73→      if (msg.role === 'assistant') {
    74→        stats.requestCount++;
    75→
    76→        // Estimate tokens (rough approximation: 1 token ≈ 4 characters)
    77→        const estimatedTokens = Math.ceil(msg.content.length / 4);
    78→        stats.completionTokens += estimatedTokens;
    79→        stats.totalTokens += estimatedTokens;
    80→
    81→        // Update last used
    82→        if (!stats.lastUsed || msg.timestamp > stats.lastUsed) {
    83→          stats.lastUsed = msg.timestamp;
    84→        }
    85→
    86→        // Estimate cost (if model info available)
    87→        if (msg.model) {
    88→          const provider = router.getProvider(msg.provider);
    89→          const model = provider?.getModel(msg.model);
    90→          if (model && model.costPer1MTokens) {
    91→            stats.estimatedCost += (estimatedTokens / 1000000) * model.costPer1MTokens;
    92→          }
    93→        }
    94→      } else if (msg.role === 'user') {
    95→        // Estimate prompt tokens
    96→        const estimatedTokens = Math.ceil(msg.content.length / 4);
    97→        stats.promptTokens += estimatedTokens;
    98→        stats.totalTokens += estimatedTokens;
    99→      }
   100→    });
   101→
   102→    return Object.values(providerStats).sort((a, b) => b.requestCount - a.requestCount);
   103→  }, [messages, timeRange, router]);
   104→
   105→  const totalRequests = useMemo(
   106→    () => usageStats.reduce((sum, stat) => sum + stat.requestCount, 0),
   107→    [usageStats]
   108→  );
   109→
   110→  const totalTokens = useMemo(
   111→    () => usageStats.reduce((sum, stat) => sum + stat.totalTokens, 0),
   112→    [usageStats]
   113→  );
   114→
   115→  const totalCost = useMemo(
   116→    () => usageStats.reduce((sum, stat) => sum + stat.estimatedCost, 0),
   117→    [usageStats]
   118→  );
   119→
   120→  const formatDate = (timestamp: number | null): string => {
   121→    if (!timestamp) return 'Never';
   122→    const date = new Date(timestamp);
   123→    const now = new Date();
   124→    const diffMs = now.getTime() - date.getTime();
   125→    const diffMins = Math.floor(diffMs / 60000);
   126→
