toolUseResult.originalFile:
/**
 * Model Selector Component
 * Select AI provider and model with comparison features
 *
 * Features:
 * - Provider and model selection
 * - Model comparison (speed, quality, context, cost)
 * - Free vs paid filtering
 * - Use case filtering
 * - Visual model ratings
 * - Context window and cost display
 */

import { useState, useMemo } from 'react';
import { AIProviderRouter } from '../services/ai/providerRouter';

interface ModelSelectorProps {
  router: AIProviderRouter;
  onSelect: (providerId: string, modelId: string) => void;
  currentProvider?: string;
  currentModel?: string;
}

export function ModelSelector({
  router,
  onSelect,
  currentProvider,
  currentModel,
}: ModelSelectorProps) {
  const [showOnlyFree, setShowOnlyFree] = useState(false);
  const [selectedUseCase, setSelectedUseCase] = useState<string>('all');
  const [selectedProvider, setSelectedProvider] = useState<string>(currentProvider || 'all');

  // Get all available models
  const allModels = useMemo(() => {
    return router.getAllAvailableModels();
  }, [router]);

  // Get unique use cases
  const useCases = useMemo(() => {
    const cases = new Set<string>();
    allModels.forEach((item) => {
      item.model.useCases?.forEach((useCase: string) => cases.add(useCase));
    });
    return Array.from(cases).sort();
  }, [allModels]);

  // Filter models
  const filteredModels = useMemo(() => {
    return allModels.filter((item) => {
      // Filter by free/paid
      if (showOnlyFree && !item.model.isFree) return false;

      // Filter by use case
      if (selectedUseCase !== 'all' && !item.model.useCases?.includes(selectedUseCase)) {
        return false;
      }

      // Filter by provider
      if (selectedProvider !== 'all' && item.providerId !== selectedProvider) {
        return false;
      }

      return true;
    });
  }, [allModels, showOnlyFree, selectedUseCase, selectedProvider]);

  // Get configured providers
  const providerStatus = router.getProviderStatus();
  const configuredProviders = Object.entries(providerStatus).filter(
    ([, status]) => status.configured // First element intentionally omitted
  );

  const handleModelSelect = (providerId: string, modelId: string) => {
    onSelect(providerId, modelId);
  };

  const renderSpeedRating = (rating: number) => {
    return (
      <div className="flex items-center gap-0.5">
        {[...Array(5)].map((_, i) => (
          <div
            key={i}
            className={`w-1.5 h-3 rounded-sm ${
              i < rating ? 'bg-accent-cyan' : 'bg-slate-500/20'
            }`}
          />
        ))}
      </div>
    );
  };

  const renderQualityRating = (rating: number) => {
    return (
      <div className="flex items-center gap-0.5">
        {[...Array(5)].map((_, i) => (
          <div
            key={i}
            className={`w-3 h-1.5 rounded-sm ${
              i < rating ? 'bg-accent-magenta' : 'bg-slate-500/20'
            }`}
          />
        ))}
      </div>
    );
  };

  const formatContextWindow = (tokens: number): string => {
    if (tokens >= 1000000) return `${(tokens / 1000000).toFixed(1)}M`;
    if (tokens >= 1000) return `${(tokens / 1000).toFixed(0)}K`;
    return `${tokens}`;
  };

  return (
    <div className="space-y-4">
      {/* Filters */}
      <div className="flex flex-wrap gap-2">
        {/* Provider Filter */}
        <select
          value={selectedProvider}
          onChange={(e) => setSelectedProvider(e.target.value)}
          className="px-3 py-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-button text-sm text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-blue"
        >
          <option value="all">All Providers</option>
          {configuredProviders.map(([providerId, status]) => (
            <option key={providerId} value={providerId}>
              {status.name}
            </option>
          ))}
        </select>

        {/* Use Case Filter */}
        <select
          value={selectedUseCase}
          onChange={(e) => setSelectedUseCase(e.target.value)}
          className="px-3 py-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-button text-sm text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-blue"
        >
          <option value="all">All Use Cases</option>
          {useCases.map((useCase) => (
            <option key={useCase} value={useCase}>
              {useCase.replace(/-/g, ' ')}
            </option>
          ))}
        </select>

        {/* Free Only Toggle */}
        <label className="flex items-center gap-2 px-3 py-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-button text-sm text-text-light-primary dark:text-text-dark-primary cursor-pointer hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-all duration-standard ease-smooth">
          <input
            type="checkbox"
            checked={showOnlyFree}
            onChange={(e) => setShowOnlyFree(e.target.checked)}
            className="accent-accent-blue"
          />
          <span>Free Only</span>
        </label>
      </div>

      {/* Results Count */}
      <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
        {filteredModels.length} model{filteredModels.length !== 1 ? 's' : ''} available
      </div>

      {/* Model List */}
      <div className="space-y-2 max-h-96 overflow-y-auto">
        {filteredModels.length === 0 ? (
          <div className="p-8 text-center text-text-light-secondary dark:text-text-dark-secondary">
            <p className="mb-2">No models found</p>
            <p className="text-sm">
              Try adjusting your filters or configure more providers in settings.
            </p>
          </div>
        ) : (
          filteredModels.map(({ providerId, providerName, model }) => {
            const isSelected =
              currentProvider === providerId && currentModel === model.id;

            return (
              <button
                key={`${providerId}-${model.id}`}
                onClick={() => handleModelSelect(providerId, model.id)}
                className={`w-full p-3 text-left rounded-button border transition-all ${
                  isSelected
                    ? 'bg-accent-blue/10 border-accent-blue'
                    : 'bg-surface-light-elevated dark:bg-surface-dark-elevated border-border-light dark:border-border-dark hover:border-accent-blue/50'
                }`}
              >
                {/* Model Header */}
                <div className="flex items-start justify-between mb-2">
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <h4 className="font-medium text-text-light-primary dark:text-text-dark-primary">
                        {model.name}
                      </h4>
                      {model.isFree && (
                        <span className="text-xs px-1.5 py-0.5 bg-green-500/10 text-green-500 rounded">
                          FREE
                        </span>
                      )}
                      {isSelected && (
                        <span className="text-xs px-1.5 py-0.5 bg-accent-blue/20 text-accent-blue rounded">
                          ✓ Active
                        </span>
                      )}
                    </div>
                    <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                      {providerName}
                    </p>
                  </div>
                </div>

                {/* Model Description */}
                {model.description && (
                  <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary mb-2">
                    {model.description}
                  </p>
                )}

                {/* Model Stats */}
                <div className="grid grid-cols-2 gap-3 text-xs">
                  {/* Speed Rating */}
                  <div>
                    <div className="text-text-light-secondary dark:text-text-dark-secondary mb-1">
                      Speed
                    </div>
                    {renderSpeedRating(model.speedRating)}
                  </div>

                  {/* Quality Rating */}
                  <div>
                    <div className="text-text-light-secondary dark:text-text-dark-secondary mb-1">
                      Quality
                    </div>
                    {renderQualityRating(model.qualityRating)}
                  </div>

                  {/* Context Window */}
                  <div>
                    <div className="text-text-light-secondary dark:text-text-dark-secondary mb-1">
                      Context
                    </div>
                    <div className="text-text-light-primary dark:text-text-dark-primary font-medium">
                      {formatContextWindow(model.contextWindow)} tokens
                    </div>
                  </div>

                  {/* Cost */}
                  <div>
                    <div className="text-text-light-secondary dark:text-text-dark-secondary mb-1">
                      Cost
                    </div>
                    <div className="text-text-light-primary dark:text-text-dark-primary font-medium">
