                    </div>
                    <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                      {providerName}
                    </p>
                  </div>
                </div>

                {/* Model Description */}
                {model.description && (
                  <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary mb-2">
                    {model.description}
                  </p>
                )}

                {/* Model Stats */}
                <div className="grid grid-cols-2 gap-3 text-xs">
                  {/* Speed Rating */}
                  <div>
                    <div className="text-text-light-secondary dark:text-text-dark-secondary mb-1">
                      Speed
                    </div>
                    {renderSpeedRating(model.speedRating)}
                  </div>

                  {/* Quality Rating */}
                  <div>
                    <div className="text-text-light-secondary dark:text-text-dark-secondary mb-1">
                      Quality
                    </div>
                    {renderQualityRating(model.qualityRating)}
                  </div>

                  {/* Context Window */}
                  <div>
                    <div className="text-text-light-secondary dark:text-text-dark-secondary mb-1">
                      Context
                    </div>
                    <div className="text-text-light-primary dark:text-text-dark-primary font-medium">
                      {formatContextWindow(model.contextWindow)} tokens
                    </div>
                  </div>

                  {/* Cost */}
                  <div>
                    <div className="text-text-light-secondary dark:text-text-dark-secondary mb-1">
                      Cost
                    </div>
                    <div className="text-text-light-primary dark:text-text-dark-primary font-medium">
                      {model.isFree ? 'Free' : `$${model.costPer1MTokens?.toFixed(2)}/1M`}
                    </div>
                  </div>
                </div>

                {/* Features */}
                <div className="mt-2 flex flex-wrap gap-1">
                  {model.supportsStreaming && (
                    <span className="text-xs px-1.5 py-0.5 bg-slate-500/10 text-slate-500 rounded">
                      Streaming
                    </span>
                  )}
                  {model.supportsVision && (
                    <span className="text-xs px-1.5 py-0.5 bg-slate-500/10 text-slate-500 rounded">
                      Vision
                    </span>
                  )}
                  {model.supportsFunctionCalling && (
                    <span className="text-xs px-1.5 py-0.5 bg-slate-500/10 text-slate-500 rounded">
                      Functions
                    </span>
                  )}
                </div>
              </button>
            );
          })
        )}
      </div>

      {/* Legend */}
      <div className="p-3 bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button">
        <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary space-y-1">
          <div className="flex items-center gap-2">
            <span className="text-accent-cyan">━━━</span>
            <span>Speed: Response time (1=slow, 5=instant)</span>
          </div>
          <div className="flex items-center gap-2">
            <span className="text-accent-magenta">━━━</span>
            <span>Quality: Output quality (1=basic, 5=excellent)</span>
          </div>
        </div>
      </div>
    </div>
  );
}

/**
 * Usage Tracker Component
 * Track AI provider usage (requests, tokens, costs)
 *
 * Features:
 * - Per-provider request counting
 * - Token usage tracking (prompt + completion)
 * - Cost estimation for paid providers
 * - Visual usage charts
 * - Export usage data
 * - Reset tracking
 */

import { useState, useMemo } from 'react';
import { useTerminalStore, type Message } from '../stores/useTerminalStore';
import { AIProviderRouter } from '../services/ai/providerRouter';

interface UsageTrackerProps {
  router: AIProviderRouter;
}

interface ProviderUsage {
  providerId: string;
  providerName: string;
  requestCount: number;
  totalTokens: number;
  promptTokens: number;
  completionTokens: number;
  estimatedCost: number;
  lastUsed: number | null;
}

export function UsageTracker({ router }: UsageTrackerProps) {
  const messages = useTerminalStore((state) => state.messages);
  const [timeRange, setTimeRange] = useState<'today' | 'week' | 'month' | 'all'>('week');

  // Calculate usage statistics from messages
  const usageStats = useMemo(() => {
    const now = Date.now();
    const cutoffTimes = {
      today: now - 24 * 60 * 60 * 1000,
      week: now - 7 * 24 * 60 * 60 * 1000,
      month: now - 30 * 24 * 60 * 60 * 1000,
      all: 0,
    };

    const cutoff = cutoffTimes[timeRange];
    const filteredMessages = messages.filter((msg) => msg.timestamp >= cutoff);

    // Group by provider
    const providerStats: Record<string, ProviderUsage> = {};

    filteredMessages.forEach((msg: Message) => {
      if (!msg.provider) return; // Skip messages without provider info

      if (!providerStats[msg.provider]) {
        const provider = router.getProvider(msg.provider);
        providerStats[msg.provider] = {
          providerId: msg.provider,
          providerName: provider?.metadata.displayName || msg.provider,
          requestCount: 0,
          totalTokens: 0,
          promptTokens: 0,
          completionTokens: 0,
          estimatedCost: 0,
          lastUsed: null,
        };
      }

      const stats = providerStats[msg.provider];

      // Count assistant messages as requests
      if (msg.role === 'assistant') {
        stats.requestCount++;

        // Estimate tokens (rough approximation: 1 token ≈ 4 characters)
        const estimatedTokens = Math.ceil(msg.content.length / 4);
        stats.completionTokens += estimatedTokens;
        stats.totalTokens += estimatedTokens;

        // Update last used
        if (!stats.lastUsed || msg.timestamp > stats.lastUsed) {
          stats.lastUsed = msg.timestamp;
        }

        // Estimate cost (if model info available)
        if (msg.model) {
          const provider = router.getProvider(msg.provider);
          const model = provider?.getModel(msg.model);
          if (model && model.costPer1MTokens) {
            stats.estimatedCost += (estimatedTokens / 1000000) * model.costPer1MTokens;
          }
        }
      } else if (msg.role === 'user') {
        // Estimate prompt tokens
        const estimatedTokens = Math.ceil(msg.content.length / 4);
        stats.promptTokens += estimatedTokens;
        stats.totalTokens += estimatedTokens;
      }
    });

    return Object.values(providerStats).sort((a, b) => b.requestCount - a.requestCount);
  }, [messages, timeRange, router]);

  const totalRequests = useMemo(
    () => usageStats.reduce((sum, stat) => sum + stat.requestCount, 0),
    [usageStats]
  );

  const totalTokens = useMemo(
    () => usageStats.reduce((sum, stat) => sum + stat.totalTokens, 0),
    [usageStats]
  );

  const totalCost = useMemo(
    () => usageStats.reduce((sum, stat) => sum + stat.estimatedCost, 0),
    [usageStats]
  );

  const formatDate = (timestamp: number | null): string => {
    if (!timestamp) return 'Never';
    const date = new Date(timestamp);
    const now = new Date();
    const diffMs = now.getTime() - date.getTime();
    const diffMins = Math.floor(diffMs / 60000);

    if (diffMins < 1) return 'Just now';
    if (diffMins < 60) return `${diffMins}m ago`;
    if (diffMins < 1440) return `${Math.floor(diffMins / 60)}h ago`;
    return date.toLocaleDateString();
  };

  const formatNumber = (num: number): string => {
    if (num >= 1000000) return `${(num / 1000000).toFixed(2)}M`;
    if (num >= 1000) return `${(num / 1000).toFixed(1)}K`;
    return num.toString();
  };

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="flex items-center justify-between">
        <h3 className="text-lg font-medium text-text-light-primary dark:text-text-dark-primary">
          Usage Statistics
        </h3>

        {/* Time Range Selector */}
        <select
          value={timeRange}
          onChange={(e) => setTimeRange(e.target.value as any)}
          className="px-3 py-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-button text-sm text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-blue"
        >
          <option value="today">Today</option>
          <option value="week">Past Week</option>
          <option value="month">Past Month</option>
          <option value="all">All Time</option>
        </select>
      </div>

      {/* Overall Stats */}
      <div className="grid grid-cols-3 gap-4">
        <div className="p-4 bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button">
          <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary mb-1">
            Total Requests
          </div>
          <div className="text-2xl font-semibold text-text-light-primary dark:text-text-dark-primary">
            {formatNumber(totalRequests)}
          </div>
        </div>

        <div className="p-4 bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button">
          <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary mb-1">
            Total Tokens
          </div>
          <div className="text-2xl font-semibold text-text-light-primary dark:text-text-dark-primary">
            {formatNumber(totalTokens)}
          </div>
        </div>

        <div className="p-4 bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button">
          <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary mb-1">
            Estimated Cost
          </div>
          <div className="text-2xl font-semibold text-text-light-primary dark:text-text-dark-primary">
            ${totalCost.toFixed(4)}
          </div>
        </div>
      </div>

      {/* Per-Provider Breakdown */}
      <div className="space-y-2">
        <h4 className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
          By Provider
        </h4>

        {usageStats.length === 0 ? (
          <div className="p-8 text-center text-text-light-secondary dark:text-text-dark-secondary">
            <p className="mb-2">No usage data for this time period</p>
            <p className="text-sm">Start a conversation to see usage statistics.</p>
          </div>
        ) : (
          <div className="space-y-2">
            {usageStats.map((stat) => {
              const requestPercent = totalRequests > 0
                ? (stat.requestCount / totalRequests) * 100
                : 0;

              return (
                <div
                  key={stat.providerId}
                  className="p-3 bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button"
                >
                  {/* Provider Name */}
                  <div className="flex items-center justify-between mb-2">
                    <h5 className="font-medium text-text-light-primary dark:text-text-dark-primary">
                      {stat.providerName}
                    </h5>
                    <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                      Last used: {formatDate(stat.lastUsed)}
                    </span>
                  </div>

                  {/* Progress Bar */}
                  <div className="mb-2 h-2 bg-surface-light dark:bg-surface-dark rounded-full overflow-hidden">
                    <div
                      className="h-full bg-accent-blue transition-all duration-300"
                      style={{ width: `${requestPercent}%` }}
                    />
                  </div>

                  {/* Stats Grid */}
                  <div className="grid grid-cols-4 gap-4 text-xs">
                    <div>
                      <div className="text-text-light-secondary dark:text-text-dark-secondary mb-0.5">
                        Requests
                      </div>
                      <div className="font-medium text-text-light-primary dark:text-text-dark-primary">
                        {formatNumber(stat.requestCount)}
                      </div>
                    </div>

                    <div>
                      <div className="text-text-light-secondary dark:text-text-dark-secondary mb-0.5">
                        Tokens
                      </div>
                      <div className="font-medium text-text-light-primary dark:text-text-dark-primary">
                        {formatNumber(stat.totalTokens)}
                      </div>
                    </div>

                    <div>
                      <div className="text-text-light-secondary dark:text-text-dark-secondary mb-0.5">
                        Cost
                      </div>
                      <div className="font-medium text-text-light-primary dark:text-text-dark-primary">
                        {stat.estimatedCost > 0 ? `$${stat.estimatedCost.toFixed(4)}` : 'Free'}
                      </div>
                    </div>

                    <div>
                      <div className="text-text-light-secondary dark:text-text-dark-secondary mb-0.5">
                        Share
                      </div>
                      <div className="font-medium text-text-light-primary dark:text-text-dark-primary">
                        {requestPercent.toFixed(1)}%
                      </div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* Notes */}
      <div className="p-3 bg-accent-blue/10 border border-accent-blue/20 rounded-button">
        <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
          <span className="font-medium text-text-light-primary dark:text-text-dark-primary">
            Note:
          </span>{' '}
          Token counts and costs are estimates based on message length (1 token ≈ 4 characters).
          Actual usage may vary. Free tier limits are not tracked here.
        </p>
      </div>
    </div>
  );
}

