  1210→// ==================== PROCESS MANAGEMENT ====================
  1211→
  1212→/**
  1213→ * Spawn a process in WebContainer
  1214→ */
  1215→export const spawn = async (
  1216→  command: string,
  1217→  args: string[],
  1218→  options?: { cwd?: string; env?: Record<string, string> }
  1219→) => {
  1220→  const container = await bootWebContainer();
  1221→  log.info('Spawning process', { command, args });
  1222→  return container.spawn(command, args, options);
