    const history = context.getHistory();
    if (history.length === 0) {
      return '\x1b[90mNo command history\x1b[0m';
    }
    return history
      .slice(-20)
      .map((entry, i) => `\x1b[90m${i + 1}.\x1b[0m ${entry.command}`)
