  1364→    bootPromise = null;
  1365→
  1366→    const store = usePhantomShellStore.getState();
  1367→    store.setWebContainer(null);
  1368→    store.setWebContainerReady(false);
  1369→    store.setDevServer(null, null);
  1370→    store.setDevServerRunning(false);
  1371→
  1372→    log.info('WebContainer references cleared');
  1373→  }
  1374→};
