  1436→#### 4.1 AI Command Service
  1437→
  1438→**File:** `src/services/phantomShell/aiCommandService.ts`
  1439→
  1440→```typescript
  1441→/**
  1442→ * AI Command Service
  1443→ *
  1444→ * Translates natural language into shell commands.
  1445→ * Uses existing AI providers from aiTerminal service.
  1446→ */
  1447→
  1448→import { aiTerminalService } from '../aiTerminal';
  1449→import { logger } from '../logger';
  1450→
  1451→const log = logger.module('PhantomShell:AICommand');
  1452→
  1453→const SYSTEM_PROMPT = `You are Phantom Shell AI, a terminal assistant for a browser-based development environment.
  1454→
  1455→Your job is to translate natural language requests into terminal commands.
  1456→
  1457→CONTEXT:
  1458→- You are running in WebContainers (Node.js in browser)
  1459→- Available: npm, npx, node, basic shell commands (ls, cd, cat, mkdir, rm, etc.)
  1460→- NOT available: git, docker, python, system-level commands
  1461→- File system is in-memory (persisted to IndexedDB)
  1462→
  1463→RESPONSE FORMAT:
  1464→- For simple requests, respond with ONLY the command(s), one per line
  1465→- For complex requests, briefly explain then provide commands
  1466→- Use npm not yarn or pnpm
  1467→- Prefer npx for one-off tools
  1468→
  1469→EXAMPLES:
  1470→User: create a react app
  1471→Response: npm create vite@latest my-app -- --template react
  1472→
  1473→User: install express
  1474→Response: npm install express
  1475→
  1476→User: show files
  1477→Response: ls -la
  1478→
  1479→DO NOT:
  1480→- Suggest git commands (git isn't available)
  1481→- Suggest python/pip commands
  1482→- Output markdown formatting (just plain text)`;
  1483→
  1484→export interface AICommandResult {
  1485→  commands: string[];
  1486→  explanation?: string;
  1487→  error?: string;
  1488→}
  1489→
  1490→export const processAICommand = async (
  1491→  prompt: string,
  1492→  context?: {
  1493→    currentDirectory?: string;
  1494→    recentOutput?: string;
  1495→  }
  1496→): Promise<AICommandResult> => {
  1497→  if (!prompt.trim()) {
  1498→    return {
  1499→      commands: [],
  1500→      error: 'Please provide a request (e.g., /ai create a react app)'
  1501→    };
  1502→  }
  1503→
  1504→  log.info('Processing AI command', { prompt: prompt.substring(0, 100) });
  1505→
  1506→  let contextMsg = '';
  1507→  if (context?.currentDirectory) {
  1508→    contextMsg += `Current directory: ${context.currentDirectory}\n`;
  1509→  }
  1510→  if (context?.recentOutput) {
  1511→    contextMsg += `Recent terminal output:\n${context.recentOutput.slice(-500)}\n`;
  1512→  }
  1513→
  1514→  const fullPrompt = contextMsg
  1515→    ? `${contextMsg}\n---\nUser request: ${prompt}`
  1516→    : prompt;
  1517→
  1518→  try {
  1519→    const response = await aiTerminalService.chat([
  1520→      { role: 'system', content: SYSTEM_PROMPT },
  1521→      { role: 'user', content: fullPrompt },
  1522→    ]);
  1523→
  1524→    const lines = response.content.trim().split('\n');
  1525→    const commands: string[] = [];
  1526→    let explanation = '';
  1527→
  1528→    for (const line of lines) {
  1529→      const trimmed = line.trim();
  1530→      if (!trimmed) continue;
  1531→
  1532→      if (looksLikeCommand(trimmed)) {
  1533→        commands.push(trimmed);
  1534→      } else {
  1535→        explanation += (explanation ? '\n' : '') + trimmed;
  1536→      }
  1537→    }
  1538→
  1539→    log.debug('AI command processed', { commandCount: commands.length });
  1540→
  1541→    return {
  1542→      commands,
  1543→      explanation: explanation || undefined,
  1544→    };
  1545→  } catch (error) {
  1546→    log.error('AI command failed', { error });
  1547→    return {
  1548→      commands: [],
  1549→      error: `AI request failed: ${error}`,
  1550→    };
  1551→  }
  1552→};
  1553→
  1554→const looksLikeCommand = (str: string): boolean => {
  1555→  const prefixes = [
  1556→    'npm ', 'npx ', 'node ', 'ls', 'cd ', 'cat ', 'mkdir ', 'rm ', 'cp ', 'mv ',
  1557→    'echo ', 'touch ', 'pwd', 'head ', 'tail ',
  1558→  ];
  1559→  const lower = str.toLowerCase();
  1560→  return prefixes.some(prefix => lower.startsWith(prefix));
  1561→};
  1562→
  1563→// Pre-defined templates for common requests (faster than AI)
  1564→export const COMMAND_TEMPLATES: Record<string, string> = {
  1565→  'create react app': 'npm create vite@latest my-app -- --template react',
  1566→  'create vue app': 'npm create vite@latest my-app -- --template vue',
  1567→  'run dev': 'npm run dev',
  1568→  'run build': 'npm run build',
  1569→  'show files': 'ls -la',
  1570→};
  1571→
  1572→export const tryTemplate = (prompt: string): string | null => {
  1573→  const lower = prompt.toLowerCase().trim();
  1574→  for (const [pattern, command] of Object.entries(COMMAND_TEMPLATES)) {
  1575→    if (lower.includes(pattern)) {
  1576→      return command;
  1577→    }
  1578→  }
  1579→  return null;
  1580→};
  1581→```
