    40→    // Quotes & dividers
    41→    'blockquote', 'hr',
    42→    // Links (href will be sanitized)
    43→    'a',
    44→    // Tables
    45→    'table', 'thead', 'tbody', 'tr', 'th', 'td',
    46→    // Other safe elements
    47→    'span', 'div',
    48→  ],
    49→  attributes: {
    50→    ...defaultSchema.attributes,
    51→    a: ['href', 'title', 'target', 'rel'],
    52→    code: ['className'], // For syntax highlighting classes
    53→    pre: ['className'],
    54→    span: ['className'],
    55→    div: ['className'],
    56→  },
    57→  // Force safe link attributes
    58→  protocols: {
    59→    href: ['http', 'https', 'mailto'],
    60→  },
    61→};
    62→
    63→export const AITerminal: React.FC = () => {
    64→  const {
    65→    isOpen,
    66→    apiKey, // Legacy Gemini key
    67→    // model is legacy and unused - destructured but not assigned to avoid TS error
    68→    activeProvider,
    69→    activeModel,
    70→    providers,
    71→    encryptionPassword,
    72→    isPasswordExpired,
    73→    fallbackEnabled,
    74→    messages,
    75→    isStreaming,
    76→    setOpen,
    77→    setActiveProvider,
    78→    addMessage,
    79→    clearMessages,
    80→    setStreaming,
    81→  } = useTerminalStore();
    82→
    83→  const [input, setInput] = useState('');
    84→  const [streamingContent, setStreamingContent] = useState('');
    85→  const [showProviderSettings, setShowProviderSettings] = useState(false);
    86→  const [showModelSelector, setShowModelSelector] = useState(false);
    87→  const [showUsageTracker, setShowUsageTracker] = useState(false);
    88→  const [fallbackNotification, setFallbackNotification] = useState<string | null>(null);
    89→
    90→  const messagesEndRef = useRef<HTMLDivElement>(null);
    91→  const inputRef = useRef<HTMLTextAreaElement>(null);
    92→  const fallbackTimeoutRef = useRef<NodeJS.Timeout | null>(null);
    93→
    94→  // Initialize provider router
    95→  const [router] = useState(() => createDefaultRouter((failedProvider, _failedModel, nextProvider, nextModel, reason) => {
    96→    // Fallback notification callback
    97→    setFallbackNotification(
    98→      `⚠️ ${failedProvider} failed: ${reason}. Switched to ${nextProvider} (${nextModel}).`
    99→    );
   100→    // Clear any existing timeout to prevent memory leaks
   101→    if (fallbackTimeoutRef.current) {
   102→      clearTimeout(fallbackTimeoutRef.current);
   103→    }
   104→    fallbackTimeoutRef.current = setTimeout(() => setFallbackNotification(null), 5000);
   105→  }));
   106→
   107→  // Cleanup timeout on unmount
   108→  useEffect(() => {
   109→    return () => {
   110→      if (fallbackTimeoutRef.current) {
   111→        clearTimeout(fallbackTimeoutRef.current);
   112→      }
   113→    };
   114→  }, []);
   115→
   116→  // Auto-scroll to bottom when messages change
   117→  useEffect(() => {
   118→    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
   119→  }, [messages, streamingContent]);
   120→
   121→  // Focus input when terminal opens
   122→  useEffect(() => {
   123→    if (isOpen) {
   124→      inputRef.current?.focus();
   125→    }
   126→  }, [isOpen]);
   127→
   128→  // Initialize AI service with API key (legacy Gemini)
   129→  useEffect(() => {
   130→    if (apiKey) {
   131→      aiTerminalService.setApiKey(apiKey);
   132→    }
   133→  }, [apiKey]);
   134→
   135→  // Configure router with active provider and model
   136→  useEffect(() => {
   137→    router.updateConfig({
   138→      primaryProvider: activeProvider,
   139→      primaryModel: activeModel,
   140→      fallbackEnabled: fallbackEnabled,
   141→    });
   142→  }, [activeProvider, activeModel, fallbackEnabled, router]);
   143→
   144→  // Initialize provider API keys from encrypted storage
   145→  useEffect(() => {
   146→    const initializeApiKeys = async () => {
   147→      if (encryptionPassword && !isPasswordExpired()) {
   148→        const allProviders = router.getAllProviders();
   149→        for (const [providerId, provider] of Object.entries(allProviders)) {
   150→          const providerConfig = providers[providerId];
   151→          if (providerConfig && providerConfig.encryptedApiKey) {
   152→            try {
   153→              const decryptedKey = await useTerminalStore.getState().getProviderApiKey(providerId, encryptionPassword);
   154→              if (decryptedKey) {
   155→                provider.setApiKey(decryptedKey);
   156→              }
   157→            } catch (error) {
   158→              console.error(`Failed to decrypt ${providerId} API key:`, error);
   159→            }
   160→          }
   161→        }
   162→      }
   163→    };
   164→
   165→    initializeApiKeys();
   166→  }, [encryptionPassword, isPasswordExpired, providers, router]);
   167→
   168→  // Keyboard shortcuts
   169→  useEffect(() => {
   170→    const handleKeyDown = (e: KeyboardEvent) => {
   171→      // Cmd/Ctrl + Shift + A to toggle terminal
   172→      if ((e.metaKey || e.ctrlKey) && e.shiftKey && e.key.toLowerCase() === 'a') {
   173→        e.preventDefault();
   174→        setOpen(!isOpen);
   175→      }
   176→    };
   177→
   178→    document.addEventListener('keydown', handleKeyDown);
   179→    return () => document.removeEventListener('keydown', handleKeyDown);
   180→  }, [isOpen, setOpen]);
   181→
   182→  const handleSubmit = async (e: React.FormEvent) => {
   183→    e.preventDefault();
   184→    if (!input.trim() || isStreaming) return;
   185→
   186→    const userMessage = input.trim();
   187→    setInput('');
   188→
   189→    // Check if any provider is configured
   190→    const configuredProviders = router.getConfiguredProviders();
   191→    if (configuredProviders.length === 0) {
   192→      addMessage({
   193→        role: 'system',
   194→        content: '⚠️ No AI providers configured. Click the ⚙️ Settings button to add API keys.',
   195→      });
   196→      return;
   197→    }
   198→
   199→    // Check if active provider is configured
   200→    const activeProviderObj = router.getProvider(activeProvider);
   201→    if (!activeProviderObj || !activeProviderObj.isConfigured()) {
   202→      addMessage({
   203→        role: 'system',
   204→        content: `⚠️ Provider "${activeProvider}" is not configured. Please add an API key in Settings.`,
   205→      });
   206→      return;
   207→    }
   208→
   209→    // Add user message
   210→    addMessage({
   211→      role: 'user',
   212→      content: userMessage,
   213→    });
   214→
   215→    // Start streaming
   216→    setStreaming(true);
   217→    setStreamingContent('');
   218→
   219→    try {
   220→      // Send message using router (with automatic fallback)
   221→      const response = await router.sendMessage({
   222→        prompt: userMessage,
   223→        conversationHistory: messages.map((msg) => ({
   224→          role: msg.role as 'user' | 'assistant' | 'system',
   225→          content: msg.content,
   226→        })),
   227→        stream: true,
   228→        onChunk: (chunk) => {
   229→          setStreamingContent((prev) => prev + chunk);
   230→        },
   231→      });
   232→
   233→      // Add complete assistant message with provider/model metadata
   234→      addMessage({
   235→        role: 'assistant',
   236→        content: response.content,
   237→        provider: response.provider || activeProvider,
   238→        model: response.model || activeModel,
   239→      });
   240→    } catch (error) {
   241→      const errorMessage = error instanceof Error ? error.message : 'Unknown error occurred';
   242→      addMessage({
   243→        role: 'system',
   244→        content: `❌ Error: ${errorMessage}`,
   245→      });
   246→    } finally{
   247→      setStreaming(false);
   248→      setStreamingContent('');
   249→    }
   250→  };
   251→
   252→  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
   253→    if (e.key === 'Enter' && !e.shiftKey) {
   254→      e.preventDefault();
   255→      handleSubmit(e);
   256→    }
   257→  };
   258→
   259→  if (!isOpen) return null;
   260→
   261→  return (
   262→    <div
   263→      className={`
   264→        fixed top-0 right-0 h-screen
   265→        transition-transform duration-200 ease-in-out
   266→        ${isOpen ? 'translate-x-0' : 'translate-x-full'}
   267→        w-[300px] lg:w-[375px]
   268→        bg-white dark:bg-black
   269→        border-l border-border-light dark:border-border-dark
   270→        shadow-2xl
   271→        z-40
   272→        flex flex-col
   273→      `}
   274→    >
   275→      {/* Header - Terminal Style */}
   276→      <div className="flex items-center justify-between px-4 py-3 bg-black dark:bg-black text-green-400 border-b border-border-light dark:border-border-dark flex-shrink-0">
   277→        <div className="flex items-center gap-2 font-mono text-sm">
   278→          <span>user@neuman-brain:~$</span>
   279→          <span className="text-green-400 text-xs">
   280→            {router.getConfiguredProviders().length > 0
   281→              ? `${activeProvider}/${activeModel}`
   282→              : 'no-provider'}
   283→          </span>
   284→        </div>
   285→
   286→        <div className="flex items-center gap-1">
   287→          {/* Fallback indicator */}
   288→          {fallbackEnabled && router.getConfiguredProviders().length > 1 && (
   289→            <span className="text-xs bg-green-400/20 px-2 py-0.5 rounded-button font-mono" title="Automatic fallback enabled">
   290→              🔄
   291→            </span>
   292→          )}
   293→
   294→          {/* Usage Tracker */}
   295→          <button
   296→            onClick={() => setShowUsageTracker(!showUsageTracker)}
   297→            className="p-1 hover:bg-green-400/20 rounded-button transition-all duration-standard ease-smooth text-sm"
   298→            title="Usage Statistics"
   299→            aria-label="View usage statistics"
   300→          >
   301→            📊
   302→          </button>
   303→
   304→          {/* Model Selector */}
   305→          <button
   306→            onClick={() => setShowModelSelector(!showModelSelector)}
   307→            className="p-1 hover:bg-green-400/20 rounded-button transition-all duration-standard ease-smooth text-sm"
   308→            title="Select Model"
   309→            aria-label="Select AI model"
   310→          >
   311→            🔀
   312→          </button>
   313→
   314→          {/* Provider Settings */}
   315→          <button
   316→            onClick={() => setShowProviderSettings(true)}
   317→            className="p-1 hover:bg-green-400/20 rounded-button transition-all duration-standard ease-smooth text-sm"
   318→            title="Provider Settings"
   319→            aria-label="Open provider settings"
   320→          >
   321→            ⚙️
   322→          </button>
   323→
   324→          {/* Close */}
   325→          <button
   326→            onClick={() => setOpen(false)}
   327→            className="p-1 hover:bg-green-400/20 rounded-button transition-all duration-standard ease-smooth text-base"
   328→            title="Close Terminal"
   329→            aria-label="Close AI terminal"
   330→          >
   331→            ✕
   332→          </button>
   333→        </div>
   334→      </div>
   335→
   336→      {/* Chat Content */}
   337→      <div className="flex flex-col flex-1 overflow-hidden">
   338→        {/* Messages */}
   339→        <div className="flex-1 overflow-y-auto p-4 space-y-4">
   340→            {/* Fallback Notification */}
   341→            {fallbackNotification && (
   342→              <div className="mb-4 p-3 bg-yellow-100 dark:bg-yellow-900/30 border border-yellow-400 dark:border-yellow-600 rounded-button text-sm text-text-light-primary dark:text-text-dark-primary">
   343→                {fallbackNotification}
   344→              </div>
   345→            )}
   346→
   347→            {messages.length === 0 && router.getConfiguredProviders().length === 0 && (
   348→              <div className="text-center py-12 text-text-light-secondary dark:text-text-dark-secondary">
   349→                <p className="text-lg font-semibold mb-2">Welcome to AI Terminal!</p>
   350→                <p className="text-sm mb-4">
   351→                  Configure AI providers to get started. Choose from 8 providers including free options!
   352→                </p>
   353→                <button
   354→                  onClick={() => setShowProviderSettings(true)}
   355→                  className="px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button transition-all duration-standard ease-smooth"
   356→                >
   357→                  ⚙️ Configure Providers
   358→                </button>
   359→                <div className="mt-4 text-xs space-y-1">
   360→                  <p className="font-medium">Free Providers Available:</p>
   361→                  <p>• OpenRouter (Llama 3.3, Gemini 2.0)</p>
   362→                  <p>• Groq (Lightning-fast inference)</p>
   363→                  <p>• HuggingFace (Thousands of models)</p>
   364→                  <p>• Mistral (European AI)</p>
   365→                </div>
   366→              </div>
   367→            )}
   368→
   369→            {messages.length === 0 && router.getConfiguredProviders().length > 0 && (
   370→              <div className="text-center py-12 text-text-light-secondary dark:text-text-dark-secondary">
   371→                <p className="text-lg font-semibold mb-2">AI Terminal Ready</p>
   372→                <p className="text-sm mb-2">
   373→                  Active: <span className="font-medium text-accent-blue">{activeProvider}</span> • {activeModel}
   374→                </p>
   375→                <p className="text-sm">Ask me anything! I can help with:</p>
   376→                <ul className="text-sm mt-2 space-y-1">
   377→                  <li>💬 General questions & conversation</li>
   378→                  <li>💻 Code generation & explanation</li>
   379→                  <li>🔧 Debugging & problem solving</li>
   380→                  <li>📝 Writing & productivity</li>
   381→                  <li>🔄 Automatic fallback if provider fails</li>
   382→                </ul>
   383→              </div>
   384→            )}
   385→
   386→            {messages.map((message) => (
   387→              <div
   388→                key={message.id}
   389→                className={`flex gap-3 ${
   390→                  message.role === 'user' ? 'justify-end' : 'justify-start'
   391→                }`}
   392→              >
   393→                {message.role !== 'user' && (
   394→                  <div className="w-8 h-8 rounded-full bg-gradient-to-r from-accent-blue to-accent-magenta flex items-center justify-center text-white flex-shrink-0">
   395→                    {message.role === 'system' ? '⚠️' : '🤖'}
