   397→                )}
   398→
   399→                <div
   400→                  className={`max-w-[80%] rounded-button px-4 py-2 font-mono ${
   401→                    message.role === 'user'
   402→                      ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-white'
   403→                      : message.role === 'system'
   404→                      ? 'bg-yellow-100 dark:bg-yellow-900/30 text-text-light-primary dark:text-text-dark-primary border border-yellow-400 dark:border-yellow-600'
   405→                      : 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-orange-600 dark:text-green-400'
   406→                  }`}
   407→                >
