   409→                    <div className="prose prose-sm dark:prose-invert max-w-none prose-headings:text-orange-600 dark:prose-headings:text-green-400 prose-code:text-orange-600 dark:prose-code:text-green-400">
   410→                      <ReactMarkdown rehypePlugins={[[rehypeSanitize, sanitizeSchema]]}>
   411→                        {message.content}
   412→                      </ReactMarkdown>
   413→                    </div>
   414→                  ) : (
   415→                    <p className="text-sm whitespace-pre-wrap">{message.content}</p>
   416→                  )}
   417→                  <div className="flex items-center gap-2 text-xs opacity-60 mt-1">
   418→                    <span>{new Date(message.timestamp).toLocaleTimeString()}</span>
   419→                    {message.provider && message.model && (
