   421→                        <span>•</span>
   422→                        <span className="font-medium" title="Provider and model used">
   423→                          {message.provider} • {message.model}
   424→                        </span>
   425→                      </>
   426→                    )}
   427→                  </div>
   428→                </div>
   429→
   430→                {message.role === 'user' && (
   431→                  <div className="w-8 h-8 rounded-full bg-accent-magenta flex items-center justify-center text-white flex-shrink-0">
   432→                    👤
   433→                  </div>
   434→                )}
   435→              </div>
   436→            ))}
   437→
   438→            {/* Streaming message */}
   439→            {isStreaming && streamingContent && (
   440→              <div className="flex gap-3 justify-start">
   441→                <div className="w-8 h-8 rounded-full bg-gradient-to-r from-accent-blue to-accent-magenta flex items-center justify-center text-white flex-shrink-0">
   442→                  🤖
   443→                </div>
   444→                <div className="max-w-[80%] rounded-button px-4 py-2 font-mono bg-surface-light-elevated dark:bg-surface-dark-elevated text-orange-600 dark:text-green-400">
   445→                  <div className="prose prose-sm dark:prose-invert max-w-none prose-headings:text-orange-600 dark:prose-headings:text-green-400 prose-code:text-orange-600 dark:prose-code:text-green-400">
   446→                    <ReactMarkdown rehypePlugins={[[rehypeSanitize, sanitizeSchema]]}>{streamingContent}</ReactMarkdown>
   447→                  </div>
   448→                  <div className="flex items-center gap-1 text-xs opacity-60 mt-1">
   449→                    <div className="w-1 h-1 bg-current rounded-full animate-pulse" />
   450→                    <div className="w-1 h-1 bg-current rounded-full animate-pulse delay-75" />
   451→                    <div className="w-1 h-1 bg-current rounded-full animate-pulse delay-150" />
   452→                  </div>
   453→                </div>
   454→              </div>
   455→            )}
   456→
   457→            <div ref={messagesEndRef} />
   458→          </div>
   459→
   460→          {/* Input Area */}
   461→          <div className="border-t border-border-light dark:border-border-dark p-3 bg-surface-light dark:bg-black flex-shrink-0">
   462→            <form onSubmit={handleSubmit} className="flex gap-2">
   463→              <textarea
   464→                ref={inputRef}
   465→                value={input}
   466→                onChange={(e) => setInput(e.target.value)}
   467→                onKeyDown={handleKeyDown}
   468→                placeholder={
   469→                  router.getConfiguredProviders().length > 0
