   472→                }
   473→                disabled={router.getConfiguredProviders().length === 0 || isStreaming}
   474→                className="flex-1 px-3 py-2 rounded-button font-mono text-sm bg-white dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark text-text-light-primary dark:text-white placeholder-text-light-secondary dark:placeholder-text-dark-secondary focus:ring-2 focus:ring-accent-blue dark:focus:ring-green-400 focus:border-transparent resize-none"
   475→                rows={1}
   476→              />
   477→              <button
   478→                type="submit"
   479→                disabled={router.getConfiguredProviders().length === 0 || !input.trim() || isStreaming}
   480→                className="px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover disabled:bg-neutral-300 dark:disabled:bg-neutral-700 text-white rounded-button font-medium transition-all duration-standard ease-smooth disabled:cursor-not-allowed"
   481→              >
   482→                {isStreaming ? '⋯' : '→'}
   483→              </button>
   484→              {messages.length > 0 && (
   485→                <button
   486→                  type="button"
   487→                  onClick={clearMessages}
   488→                  className="px-3 py-2 bg-surface-light-elevated dark:bg-surface-dark hover:bg-neutral-200 dark:hover:bg-neutral-700 text-text-light-primary dark:text-text-dark-primary rounded-button text-sm transition-all duration-standard ease-smooth"
   489→                  title="Clear chat"
   490→                >
   491→                  🗑️
   492→                </button>
   493→              )}
   494→            </form>
   495→          </div>
   496→        </div>
   497→
   498→      {/* Provider Settings Modal */}
   499→      <ProviderSettings
   500→        isOpen={showProviderSettings}
   501→        onClose={() => setShowProviderSettings(false)}
   502→        router={router}
   503→      />
   504→
   505→      {/* Model Selector Sliding Panel */}
   506→      {showModelSelector && (
   507→        <div className="absolute top-12 right-0 w-80 max-h-[70vh] bg-white dark:bg-surface-dark-elevated border-l border-border-light dark:border-border-dark shadow-xl overflow-hidden flex flex-col">
   508→          <div className="p-3 border-b border-border-light dark:border-border-dark flex items-center justify-between bg-surface-light dark:bg-surface-dark flex-shrink-0">
   509→            <h3 className="font-semibold text-sm text-text-light-primary dark:text-text-dark-primary">
   510→              Select Model
   511→            </h3>
   512→            <button
   513→              onClick={() => setShowModelSelector(false)}
   514→              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-neutral-800 rounded-button"
   515→            >
   516→              ✕
   517→            </button>
   518→          </div>
   519→          <div className="p-3 overflow-y-auto flex-1">
   520→            <ModelSelector
   521→              router={router}
   522→              onSelect={(providerId, modelId) => {
   523→                setActiveProvider(providerId, modelId);
   524→                setShowModelSelector(false);
   525→              }}
   526→              currentProvider={activeProvider}
   527→              currentModel={activeModel}
   528→            />
   529→          </div>
   530→        </div>
   531→      )}
   532→
   533→      {/* Usage Tracker Sliding Panel */}
   534→      {showUsageTracker && (
   535→        <div className="absolute top-12 right-0 w-80 max-h-[70vh] bg-white dark:bg-surface-dark-elevated border-l border-border-light dark:border-border-dark shadow-xl overflow-hidden flex flex-col">
   536→          <div className="p-3 border-b border-border-light dark:border-border-dark flex items-center justify-between bg-surface-light dark:bg-surface-dark flex-shrink-0">
   537→            <h3 className="font-semibold text-sm text-text-light-primary dark:text-text-dark-primary">
   538→              Usage Tracker
   539→            </h3>
   540→            <button
   541→              onClick={() => setShowUsageTracker(false)}
   542→              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-neutral-800 rounded-button"
   543→            >
   544→              ✕
   545→            </button>
   546→          </div>
   547→          <div className="p-3 overflow-y-auto flex-1">
   548→            <UsageTracker router={router} />
   549→          </div>
   550→        </div>
   551→      )}
   552→    </div>
   553→  );
   554→};
